function addRegression(
  spec: HardProblemSpec,
  input: string,
  expectedOutput: string,
): HardProblemSpec["tests"] {
  return [...spec.tests, [input, expectedOutput]];
}

function correctHardProblem(original: HardProblemSpec): HardProblemSpec {
  const spec = {
    ...original,
    input: clarifiedInputs[original.id] ?? original.input,
  };

  switch (spec.id) {
    case "v5-two-array-median":
      return {
        ...spec,
        solution: `first = list(map(int, input().split()))
second = list(map(int, input().split()))
if len(first) > len(second):
    first, second = second, first
total = len(first) + len(second)
left_size = (total + 1) // 2
low, high = 0, len(first)
while low <= high:
    cut_first = (low + high) // 2
    cut_second = left_size - cut_first
    a_left = first[cut_first - 1] if cut_first else None
    a_right = first[cut_first] if cut_first < len(first) else None
    b_left = second[cut_second - 1] if cut_second else None
    b_right = second[cut_second] if cut_second < len(second) else None
    left_ok = a_left is None or b_right is None or a_left <= b_right
    right_ok = b_left is None or a_right is None or b_left <= a_right
    if left_ok and right_ok:
        left_middle = b_left if a_left is None else a_left if b_left is None else max(a_left, b_left)
        if total % 2:
            print(f'{left_middle}.0')
        else:
            right_middle = b_right if a_right is None else a_right if b_right is None else min(a_right, b_right)
            middle_sum = left_middle + right_middle
            if middle_sum % 2 == 0:
                print(f'{middle_sum // 2}.0')
            else:
                sign = '-' if middle_sum < 0 else ''
                print(f'{sign}{abs(middle_sum) // 2}.5')
        break
    if a_left is not None and b_right is not None and a_left > b_right:
        high = cut_first - 1
    else:
        low = cut_first + 1`,
        tests: addRegression(
          spec,
          "9007199254740992\n9007199254740993",
          "9007199254740992.5",
        ),
      };
    case "v5-edge-budget-route":
      return {
        ...spec,
        solution: `n, edge_count = map(int, input().split())
edges = [tuple(map(int, input().split())) for _ in range(edge_count)]
start, end, limit = map(int, input().split())
best = [None] * n
best[start] = 0
for _ in range(limit):
    updated = best[:]
    for left, right, cost in edges:
        if best[left] is not None:
            candidate = best[left] + cost
            if updated[right] is None or candidate < updated[right]:
                updated[right] = candidate
    best = updated
print(-1 if best[end] is None else best[end])`,
        tests: addRegression(
          spec,
          "2 1\n0 1 1000000000000000000000000000000\n0 1 1",
          "1000000000000000000000000000000",
        ),
      };
    case "v5-divide-closest-points":
      return {
        ...spec,
        solution: `def closest(points):
    if len(points) <= 3:
        best = None
        for first in range(len(points)):
            for second in range(first + 1, len(points)):
                dx = points[first][0] - points[second][0]
                dy = points[first][1] - points[second][1]
                distance = dx * dx + dy * dy
                if best is None or distance < best:
                    best = distance
        return best, sorted(points, key=lambda point: point[1])
    middle = len(points) // 2
    dividing_x = points[middle][0]
    left_best, left_y = closest(points[:middle])
    right_best, right_y = closest(points[middle:])
    best = min(left_best, right_best)
    merged = []
    left = right = 0
    while left < len(left_y) and right < len(right_y):
        if left_y[left][1] <= right_y[right][1]:
            merged.append(left_y[left]); left += 1
        else:
            merged.append(right_y[right]); right += 1
    merged += left_y[left:] + right_y[right:]
    strip = [point for point in merged if (point[0] - dividing_x) ** 2 < best]
    for first in range(len(strip)):
        second = first + 1
        while second < len(strip) and (strip[second][1] - strip[first][1]) ** 2 < best:
            dx = strip[first][0] - strip[second][0]
            dy = strip[first][1] - strip[second][1]
            best = min(best, dx * dx + dy * dy)
            second += 1
    return best, merged

points = [tuple(map(int, input().split())) for _ in range(int(input()))]
points.sort()
print(closest(points)[0])`,
        tests: addRegression(
          spec,
          "2\n0 0\n1000000000000000000000 0",
          "1000000000000000000000000000000000000000000",
        ),
      };
    case "v5-ratio-equation-queries":
      return {
        ...spec,
        output:
          "One result per query rounded to five decimal places (exact halves round upward), or `-1.00000` when either variable is unknown or no relation connects them.",
        solution: `equation_count = int(input())
graph = {}
for _ in range(equation_count):
    left, right, ratio_text = input().split()
    if '.' in ratio_text:
        whole, fractional = ratio_text.split('.', 1)
        numerator = int(whole + fractional)
        denominator = 10 ** len(fractional)
    else:
        numerator = int(ratio_text)
        denominator = 1
    first, second = numerator, denominator
    while second:
        first, second = second, first % second
    numerator //= first
    denominator //= first
    graph.setdefault(left, []).append((right, numerator, denominator))
    graph.setdefault(right, []).append((left, denominator, numerator))
for _ in range(int(input())):
    start, end = input().split()
    answer = None
    if start in graph and end in graph:
        stack = [(start, 1, 1)]
        seen = {start}
        while stack:
            node, value_numerator, value_denominator = stack.pop()
            if node == end:
                answer = value_numerator, value_denominator
                break
            for neighbor, edge_numerator, edge_denominator in graph[node]:
                if neighbor not in seen:
                    seen.add(neighbor)
                    first, second = value_numerator, edge_denominator
                    while second:
                        first, second = second, first % second
                    cross_one = first
                    first, second = edge_numerator, value_denominator
                    while second:
                        first, second = second, first % second
                    cross_two = first
                    next_numerator = (value_numerator // cross_one) * (edge_numerator // cross_two)
                    next_denominator = (value_denominator // cross_two) * (edge_denominator // cross_one)
                    stack.append((neighbor, next_numerator, next_denominator))
    if answer is None:
        print('-1.00000')
    else:
        numerator, denominator = answer
        rounded, remainder = divmod(numerator * 100_000, denominator)
        if remainder * 2 >= denominator:
            rounded += 1
        print(f'{rounded // 100_000}.{rounded % 100_000:05d}')`,
        tests: addRegression(
          spec,
          "2\nx y 9007199254740993\na b 0.000005\n2\nx y\na b",
          "9007199254740993.00000\n0.00001",
        ),
      };
    case "v5-lazy-range-minimum":
      return {
        ...spec,
        solution: spec.solution.replace("answer = 10 ** 30", "answer = float('inf')"),
        tests: addRegression(
          spec,
          "10000000000000000000000000000000 20000000000000000000000000000000\n1\nMIN 1 1",
          "20000000000000000000000000000000",
        ),
      };
    case "v5-largest-remainder-split":
      return {
        ...spec,
        solution: `from decimal import Decimal

amount = Decimal(input())
numerator, denominator = amount.as_integer_ratio()
cents = numerator * 100 // denominator
weights = list(map(int, input().split()))
weight_sum = sum(weights)
shares = []
remainders = []
for weight in weights:
    share, remainder = divmod(cents * weight, weight_sum)
    shares.append(share)
    remainders.append(remainder)
remaining = cents - sum(shares)
order = sorted(range(len(weights)), key=lambda index: (-remainders[index], index))
for index in order[:remaining]:
    shares[index] += 1
print(' '.join(f'{share // 100}.{share % 100:02d}' for share in shares))`,
        tests: addRegression(
          spec,
          "123456789012345678901234567890.12\n1",
          "123456789012345678901234567890.12",
        ),
      };
    case "v5-csv-revenue-winner":
      return {
        ...spec,
        solution: `import csv
from decimal import Decimal

best_item = None
best_revenue_cents = None
for _ in range(int(input())):
    item, quantity, price = next(csv.reader([input()]))
    numerator, denominator = Decimal(price).as_integer_ratio()
    revenue_cents = int(quantity) * numerator * 100 // denominator
    if best_revenue_cents is None or revenue_cents > best_revenue_cents or (revenue_cents == best_revenue_cents and item < best_item):
        best_item = item
        best_revenue_cents = revenue_cents
print(best_item, f'{best_revenue_cents // 100}.{best_revenue_cents % 100:02d}')`,
        tests: addRegression(
          spec,
          "1\nHuge,123456789012345678901234567890,1.23",
          "Huge 151851850485185185048518518504.70",
        ),
      };
    default:
      return spec;
  }
}

function p(spec: HardProblemSpec): Problem {
  return createProblem(correctHardProblem(spec));
}

const fundamentalProblems: Problem[] = [
  p({ difficulty: "hard", id: "v5-modular-power-tower", title: "Modular Power Tower", tags: ["algorithms", "numbers", "modular-arithmetic"], summary: "Evaluate a power tower `a^(b^c)` modulo a prime without constructing its enormous exponent.", input: "Four integers `a b c p`, where `p` is prime, `1 <= a,b < p`, `1 <= c <= 10^18`, and `a` is not divisible by `p`.", output: "`a^(b^c) mod p` as an integer from 0 through `p-1`.", solution: "a, b, c, prime = map(int, input().split())\nexponent = pow(b, c, prime - 1)\nprint(pow(a, exponent, prime))", tests: [["2 3 4 5", "2"], ["7 2 10 13", "9"], ["3 4 5 17", "1"]] }),
  p({ difficulty: "hard", id: "v5-total-binary-ones", title: "Binary Ones Across a Range", tags: ["algorithms", "numbers", "bitwise"], summary: "Count all `1` bits appearing in the binary representations of every integer from 0 through `n` in logarithmic time.", input: "One integer `n` with `0 <= n <= 10^18`.", output: "The total number of set bits across the inclusive range.", solution: "n = int(input())\ntotal = 0\nbit = 1\nwhile bit <= n:\n    cycle = bit * 2\n    full_cycles = (n + 1) // cycle\n    total += full_cycles * bit\n    total += max(0, (n + 1) % cycle - bit)\n    bit *= 2\nprint(total)", tests: [["5", "7"], ["0", "0"], ["10", "17"]] }),
  p({ difficulty: "hard", id: "v5-fast-linear-recurrence", title: "Fast Linear Recurrence", tags: ["algorithms", "numbers", "fast-exponentiation"], summary: "Find a far-away term of a second-order linear recurrence using scalar matrix exponentiation.", input: "Six integers `t0 t1 a b n m`. The recurrence is `T(n)=a*T(n-1)+b*T(n-2)`, `0 <= n <= 10^18`, and `2 <= m <= 10^9`.", output: "`T(n) mod m`.", solution: "t0, t1, a, b, n, mod = map(int, input().split())\nif n == 0:\n    print(t0 % mod)\nelse:\n    p00, p01, p10, p11 = a % mod, b % mod, 1, 0\n    r00, r01, r10, r11 = 1, 0, 0, 1\n    exponent = n - 1\n    while exponent:\n        if exponent & 1:\n            r00, r01, r10, r11 = ((r00 * p00 + r01 * p10) % mod, (r00 * p01 + r01 * p11) % mod, (r10 * p00 + r11 * p10) % mod, (r10 * p01 + r11 * p11) % mod)\n        p00, p01, p10, p11 = ((p00 * p00 + p01 * p10) % mod, (p00 * p01 + p01 * p11) % mod, (p10 * p00 + p11 * p10) % mod, (p10 * p01 + p11 * p11) % mod)\n        exponent //= 2\n    print((r00 * t1 + r01 * t0) % mod)", tests: [["0 1 1 1 10 1000", "55"], ["2 3 2 1 4 100", "46"], ["17 9 5 7 0 13", "4"]] }),
  p({ difficulty: "hard", id: "v5-square-sum-theorem", title: "Fewest Square Summands", tags: ["algorithms", "numbers", "number-theory"], summary: "Use the sum-of-squares theorems to find the fewest positive perfect squares whose sum is `n`.", input: "One integer `n` with `1 <= n <= 10^12`.", output: "The minimum number of square summands: 1, 2, 3, or 4.", solution: "n = int(input())\nroot = int(n ** 0.5)\nwhile (root + 1) * (root + 1) <= n:\n    root += 1\nwhile root * root > n:\n    root -= 1\nif root * root == n:\n    print(1)\nelse:\n    two = False\n    first = 1\n    second = root\n    while first <= second:\n        total = first * first + second * second\n        if total == n:\n            two = True\n            break\n        if total < n:\n            first += 1\n        else:\n            second -= 1\n    if two:\n        print(2)\n    else:\n        reduced = n\n        while reduced % 4 == 0:\n            reduced //= 4\n        print(4 if reduced % 8 == 7 else 3)", tests: [["12", "3"], ["13", "2"], ["7", "4"]] }),
];

const loopProblems: Problem[] = [
  p({ difficulty: "hard", id: "v5-factorial-base-zeroes", title: "Factorial Zeroes in Any Base", tags: ["loops", "number-theory"], summary: "Count the trailing zeroes of `n!` when it is written in an arbitrary base by balancing the base's prime factors.", input: "Two integers `n b` with `1 <= n <= 10^18` and `2 <= b <= 10^9`.", output: "The number of trailing base-`b` zeroes in `n!`.", solution: "n, base = map(int, input().split())\nfactors = []\nvalue = base\nprime = 2\nwhile prime * prime <= value:\n    if value % prime == 0:\n        amount = 0\n        while value % prime == 0:\n            value //= prime\n            amount += 1\n        factors.append((prime, amount))\n    prime += 1\nif value > 1:\n    factors.append((value, 1))\nanswer = n\nfor prime, needed in factors:\n    available = 0\n    power = prime\n    while power <= n:\n        available += n // power\n        if power > n // prime:\n            break\n        power *= prime\n    answer = min(answer, available // needed)\nprint(answer)", tests: [["10 12", "4"], ["25 10", "6"], ["8 16", "1"]] }),
  p({ difficulty: "hard", id: "v5-pisano-cycle-length", title: "Pisano Cycle Length", tags: ["loops", "cycles", "numbers"], summary: "Find when Fibonacci numbers modulo `m` return to the starting pair `0, 1`.", input: "One integer `m` with `2 <= m <= 1000`.", output: "The length of the Fibonacci remainder cycle modulo `m`.", solution: "mod = int(input())\nprevious, current = 0, 1\nlength = 0\nwhile True:\n    previous, current = current, (previous + current) % mod\n    length += 1\n    if previous == 0 and current == 1:\n        break\nprint(length)", tests: [["2", "3"], ["3", "8"], ["10", "60"]] }),
  p({ difficulty: "hard", id: "v5-josephus-safe-seat", title: "Josephus Safe Seat", tags: ["loops", "recurrences", "simulation"], summary: "Find the final surviving seat in a huge circular elimination game without simulating the circle.", input: "Two integers `n k` with `1 <= n <= 10^7` and `1 <= k <= 10^18`. Starting at seat 1, every `k`th remaining seat is removed.", output: "The one-based number of the surviving seat.", solution: "n, step = map(int, input().split())\nsurvivor = 0\nsize = 2\nwhile size <= n:\n    survivor = (survivor + step) % size\n    size += 1\nprint(survivor + 1)", tests: [["7 3", "4"], ["5 2", "3"], ["1 99", "1"]] }),
  p({ difficulty: "hard", id: "v5-kaprekar-orbit", title: "Kaprekar's Four-Digit Orbit", tags: ["loops", "simulation", "numbers"], summary: "Trace the four-digit Kaprekar process until it reaches 6174.", input: "Exactly four decimal digits, including possible leading zeroes. At least two digits differ.", output: "First print the number of transformations. Then print the full orbit from the input through `6174`, zero-padding every term to four digits.", solution: "current = input().strip()\norbit = [current]\nwhile current != '6174':\n    ascending = ''.join(sorted(current))\n    descending = ascending[::-1]\n    current = f'{int(descending) - int(ascending):04d}'\n    orbit.append(current)\nprint(len(orbit) - 1)\nprint(' '.join(orbit))", tests: [["3524", "3\n3524 3087 8352 6174"], ["2111", "5\n2111 0999 8991 8082 8532 6174"], ["6174", "0\n6174"]] }),
];

const stringProblems: Problem[] = [
  p({ difficulty: "hard", id: "v5-shortest-front-palindrome", title: "Shortest Front-Built Palindrome", tags: ["strings", "prefix-function", "algorithms"], summary: "Make a string palindromic by prepending as few characters as possible.", input: "One non-empty lowercase string of at most 200,000 characters.", output: "The unique shortest palindrome obtainable only by prepending characters.", solution: "text = input()\ncombined = text + '#' + text[::-1]\nprefix = [0] * len(combined)\nfor index in range(1, len(combined)):\n    length = prefix[index - 1]\n    while length and combined[index] != combined[length]:\n        length = prefix[length - 1]\n    if combined[index] == combined[length]:\n        length += 1\n    prefix[index] = length\nadd = text[prefix[-1]:][::-1]\nprint(add + text)", tests: [["abcd", "dcbabcd"], ["aacecaaa", "aaacecaaa"], ["racecar", "racecar"]] }),
  p({ difficulty: "hard", id: "v5-minimum-cyclic-rotation", title: "Lexicographically Smallest Rotation", tags: ["strings", "booth-algorithm", "algorithms"], summary: "Find the alphabetically earliest cyclic rotation in linear time.", input: "One non-empty lowercase string of at most 200,000 characters.", output: "Its lexicographically smallest cyclic rotation.", solution: "text = input()\ndoubled = text + text\nlength = len(text)\ni, j, offset = 0, 1, 0\nwhile i < length and j < length and offset < length:\n    left = doubled[i + offset]\n    right = doubled[j + offset]\n    if left == right:\n        offset += 1\n        continue\n    if left > right:\n        i = i + offset + 1\n        if i == j:\n            i += 1\n    else:\n        j = j + offset + 1\n        if i == j:\n            j += 1\n    offset = 0\nstart = min(i, j)\nprint(doubled[start:start + length])", tests: [["caba", "abac"], ["bbbb", "bbbb"], ["zebra", "azebr"]] }),
  p({ difficulty: "hard", id: "v5-full-glob-match", title: "Full Glob Match", tags: ["strings", "dynamic-programming", "patterns"], summary: "Decide whether an entire text matches a glob pattern where `?` matches one character and `*` matches any sequence.", input: "A text on the first line and a pattern on the second. Both contain lowercase letters; only the pattern may contain `?` and `*`.", output: "`match` if the whole text matches, otherwise `no match`.", solution: "text = input()\npattern = input()\nprevious = [True] + [False] * len(text)\nfor token in pattern:\n    current = [False] * (len(text) + 1)\n    if token == '*':\n        current[0] = previous[0]\n        for index in range(1, len(text) + 1):\n            current[index] = previous[index] or current[index - 1]\n    else:\n        for index in range(1, len(text) + 1):\n            current[index] = previous[index - 1] and (token == '?' or token == text[index - 1])\n    previous = current\nprint('match' if previous[-1] else 'no match')", tests: [["adceb\n*a*b", "match"], ["acdcb\na*c?b", "no match"], ["abc\na??", "match"]] }),
  p({ difficulty: "hard", id: "v5-target-subsequence-count", title: "Target Subsequence Count", tags: ["strings", "dynamic-programming", "counting"], summary: "Count how many index subsequences of a source spell a target exactly.", input: "A source string, then a target string. Both are non-empty lowercase strings of length at most 1000.", output: "The exact number of matching index subsequences.", solution: "source = input()\ntarget = input()\nways = [1] + [0] * len(target)\nfor character in source:\n    for index in range(len(target) - 1, -1, -1):\n        if character == target[index]:\n            ways[index + 1] += ways[index]\nprint(ways[-1])", tests: [["rabbbit\nrabbit", "3"], ["babgbag\nbag", "5"], ["abc\nabcd", "0"]] }),
  p({ difficulty: "hard", id: "v5-palindrome-cut-count", title: "Minimum Palindrome Cuts", tags: ["strings", "dynamic-programming", "palindromes"], summary: "Split a string into palindromic pieces using the fewest cuts.", input: "One non-empty lowercase string of at most 2000 characters.", output: "The minimum number of cuts between pieces.", solution: "text = input()\nlength = len(text)\ncuts = list(range(-1, length))\npalindromes = [False] * length\nfor end in range(length):\n    next_row = [False] * length\n    for start in range(end + 1):\n        if text[start] == text[end] and (end - start < 2 or palindromes[start + 1]):\n            next_row[start] = True\n            cuts[end + 1] = min(cuts[end + 1], cuts[start] + 1)\n    palindromes = next_row\nprint(cuts[length])", tests: [["aab", "1"], ["abccbc", "2"], ["racecar", "0"]] }),
  p({ difficulty: "hard", id: "v5-nested-repeat-decoder", title: "Nested Repeat Decoder", tags: ["strings", "parsing", "nested-structure"], summary: "Decode nested repeat groups such as `3[a2[c]]`.", input: "One valid encoding made of lowercase letters, positive integer repeat counts, and brackets. The decoded result has at most 100,000 characters.", output: "The fully decoded string.", solution: "encoded = input()\ncounts = []\nparts = []\ncurrent = ''\nnumber = 0\nfor character in encoded:\n    if character.isdigit():\n        number = number * 10 + int(character)\n    elif character == '[':\n        counts.append(number)\n        parts.append(current)\n        number = 0\n        current = ''\n    elif character == ']':\n        current = parts.pop() + current * counts.pop()\n    else:\n        current += character\nprint(current)", tests: [["3[a2[c]]", "accaccacc"], ["2[ab]3[c]", "ababccc"], ["10[z]", "zzzzzzzzzz"]] }),
  p({ difficulty: "hard", id: "v5-smallest-cover-window", title: "Smallest Character Cover", tags: ["strings", "sliding-window", "algorithms"], summary: "Find the shortest substring containing every required character with its required multiplicity.", input: "A text, then a non-empty requirement string. Both contain letters only.", output: "The shortest covering substring; on equal lengths choose the earliest. Print `none` if no cover exists.", solution: "text = input()\nrequired = input()\nneed = {}\nfor character in required:\n    need[character] = need.get(character, 0) + 1\nhave = {}\nformed = 0\nleft = 0\nbest = None\nfor right, character in enumerate(text):\n    have[character] = have.get(character, 0) + 1\n    if character in need and have[character] == need[character]:\n        formed += 1\n    while formed == len(need):\n        if best is None or right - left + 1 < best[0]:\n            best = (right - left + 1, left, right)\n        outgoing = text[left]\n        have[outgoing] -= 1\n        if outgoing in need and have[outgoing] < need[outgoing]:\n            formed -= 1\n        left += 1\nprint('none' if best is None else text[best[1]:best[2] + 1])", tests: [["ADOBECODEBANC\nABC", "BANC"], ["aaabcbc\naabc", "aabc"], ["hello\nxyz", "none"]] }),
  p({ difficulty: "hard", id: "v5-remove-digits-minimum", title: "Remove Digits for the Minimum", tags: ["strings", "greedy", "monotonic-stack"], summary: "Delete exactly `k` digits from a decimal number to make the smallest possible value.", input: "A non-empty decimal string, then `k` with `0 <= k <= length`.", output: "The smallest remaining value without leading zeroes, or `0` if no nonzero digits remain.", solution: "digits = input().strip()\nremove = int(input())\nstack = []\nfor digit in digits:\n    while remove and stack and stack[-1] > digit:\n        stack.pop()\n        remove -= 1\n    stack.append(digit)\nif remove:\n    stack = stack[:-remove]\nanswer = ''.join(stack).lstrip('0')\nprint(answer or '0')", tests: [["1432219\n3", "1219"], ["10200\n1", "200"], ["10\n2", "0"]] }),
  p({ difficulty: "hard", id: "v5-sentence-segmentation-count", title: "Sentence Segmentation Count", tags: ["strings", "dynamic-programming", "parsing"], summary: "Count how many ways a text can be split into supplied words.", input: "A non-empty lowercase text, an integer `n`, then `n` distinct non-empty lowercase words. Text length is at most 5000.", output: "The number of complete segmentations modulo 1,000,000,007.", solution: "text = input()\nword_count = int(input())\nwords = [input() for _ in range(word_count)]\nby_first = {}\nfor word in words:\n    by_first.setdefault(word[0], []).append(word)\nways = [0] * (len(text) + 1)\nways[0] = 1\nmod = 1_000_000_007\nfor start in range(len(text)):\n    if ways[start] == 0:\n        continue\n    for word in by_first.get(text[start], []):\n        if text.startswith(word, start):\n            ways[start + len(word)] = (ways[start + len(word)] + ways[start]) % mod\nprint(ways[-1])", tests: [["catsanddog\n5\ncat\ncats\nand\nsand\ndog", "2"], ["aaaa\n2\na\naa", "5"], ["applepenapple\n2\napple\npen", "1"]] }),
  p({ difficulty: "hard", id: "v5-interleaving-strings", title: "Interleaving String Check", tags: ["strings", "dynamic-programming", "weaving"], summary: "Determine whether a target interleaves two strings while preserving the character order of each.", input: "The first string, second string, and target on separate lines. All are lowercase and non-empty.", output: "`yes` if the target is a valid interleaving, otherwise `no`.", solution: "first = input()\nsecond = input()\ntarget = input()\nif len(target) != len(first) + len(second):\n    print('no')\nelse:\n    possible = [False] * (len(second) + 1)\n    possible[0] = True\n    for j in range(1, len(second) + 1):\n        possible[j] = possible[j - 1] and second[j - 1] == target[j - 1]\n    for i in range(1, len(first) + 1):\n        possible[0] = possible[0] and first[i - 1] == target[i - 1]\n        for j in range(1, len(second) + 1):\n            position = i + j - 1\n            possible[j] = (possible[j] and first[i - 1] == target[position]) or (possible[j - 1] and second[j - 1] == target[position])\n    print('yes' if possible[-1] else 'no')", tests: [["aabcc\ndbbca\naadbbcbcac", "yes"], ["aabcc\ndbbca\naadbbbaccc", "no"], ["ab\ncd\nacbd", "yes"]] }),
  p({ difficulty: "hard", id: "v5-string-repetition-exponent", title: "String Repetition Exponent", tags: ["strings", "prefix-function", "periodicity"], summary: "Find how many times the shortest repeating unit is repeated to form a string.", input: "One non-empty string of at most 200,000 lowercase letters.", output: "The largest integer `k` such that the string is exactly `k` copies of some substring.", solution: "text = input()\nprefix = [0] * len(text)\nfor index in range(1, len(text)):\n    length = prefix[index - 1]\n    while length and text[index] != text[length]:\n        length = prefix[length - 1]\n    if text[index] == text[length]:\n        length += 1\n    prefix[index] = length\nperiod = len(text) - prefix[-1]\nprint(len(text) // period if len(text) % period == 0 else 1)", tests: [["abcabcabc", "3"], ["aaaaa", "5"], ["ababa", "1"]] }),
  p({ difficulty: "hard", id: "v5-smallest-distinct-subsequence", title: "Smallest Distinct Subsequence", tags: ["strings", "greedy", "monotonic-stack"], summary: "Keep each distinct character exactly once while producing the lexicographically smallest possible subsequence.", input: "One non-empty lowercase string.", output: "The lexicographically smallest subsequence containing every distinct input character once.", solution: "text = input()\nlast = {character: index for index, character in enumerate(text)}\nstack = []\nused = set()\nfor index, character in enumerate(text):\n    if character in used:\n        continue\n    while stack and character < stack[-1] and last[stack[-1]] > index:\n        used.remove(stack.pop())\n    stack.append(character)\n    used.add(character)\nprint(''.join(stack))", tests: [["cbacdcbc", "acdb"], ["bcabc", "abc"], ["zyxz", "yxz"]] }),
];

const listProblems: Problem[] = [
  p({ difficulty: "hard", id: "v5-longest-increasing-count", title: "Count Longest Increasing Subsequences", tags: ["lists", "dynamic-programming", "counting"], summary: "Find both the length of a longest strictly increasing subsequence and how many index subsequences attain it.", input: "A line of 1 to 2000 space-separated integers. Equal values at different indices are distinct choices.", output: "The maximum length and the exact number of subsequences, separated by a space.", solution: "values = list(map(int, input().split()))\nlengths = [1] * len(values)\ncounts = [1] * len(values)\nfor right in range(len(values)):\n    for left in range(right):\n        if values[left] < values[right]:\n            candidate = lengths[left] + 1\n            if candidate > lengths[right]:\n                lengths[right] = candidate\n                counts[right] = counts[left]\n            elif candidate == lengths[right]:\n                counts[right] += counts[left]\nbest = max(lengths)\nprint(best, sum(count for length, count in zip(lengths, counts) if length == best))", tests: [["1 3 5 4 7", "4 2"], ["2 2 2 2", "1 4"], ["1 2 3", "3 1"]] }),
  p({ difficulty: "hard", id: "v5-inversion-total", title: "Inversion Total", tags: ["lists", "sorting", "bottom-up-merge"], summary: "Count pairs of indices that appear in the opposite order from their values.", input: "A line of 1 to 200,000 integers.", output: "The number of pairs `(i,j)` with `i < j` and `values[i] > values[j]`.", solution: "values = list(map(int, input().split()))\nbuffer = [0] * len(values)\nwidth = 1\ninversions = 0\nwhile width < len(values):\n    for start in range(0, len(values), 2 * width):\n        middle = min(start + width, len(values))\n        end = min(start + 2 * width, len(values))\n        left, right, write = start, middle, start\n        while left < middle and right < end:\n            if values[left] <= values[right]:\n                buffer[write] = values[left]\n                left += 1\n            else:\n                buffer[write] = values[right]\n                right += 1\n                inversions += middle - left\n            write += 1\n        while left < middle:\n            buffer[write] = values[left]\n            left += 1\n            write += 1\n        while right < end:\n            buffer[write] = values[right]\n            right += 1\n            write += 1\n    values, buffer = buffer, values\n    width *= 2\nprint(inversions)", tests: [["2 4 1 3 5", "3"], ["5 4 3 2 1", "10"], ["1 1 1", "0"]] }),
  p({ difficulty: "hard", id: "v5-two-array-median", title: "Median of Two Sorted Arrays", tags: ["lists", "searching", "binary-search"], summary: "Find the combined median of two sorted arrays without merging them.", input: "Two lines of sorted integers; each line is non-empty and the total length is at most 200,000.", output: "The combined median with exactly one digit after the decimal point.", solution: "first = list(map(int, input().split()))\nsecond = list(map(int, input().split()))\nif len(first) > len(second):\n    first, second = second, first\ntotal = len(first) + len(second)\nleft_size = (total + 1) // 2\nlow, high = 0, len(first)\nwhile low <= high:\n    cut_first = (low + high) // 2\n    cut_second = left_size - cut_first\n    a_left = first[cut_first - 1] if cut_first else float('-inf')\n    a_right = first[cut_first] if cut_first < len(first) else float('inf')\n    b_left = second[cut_second - 1] if cut_second else float('-inf')\n    b_right = second[cut_second] if cut_second < len(second) else float('inf')\n    if a_left <= b_right and b_left <= a_right:\n        if total % 2:\n            median = max(a_left, b_left)\n        else:\n            median = (max(a_left, b_left) + min(a_right, b_right)) / 2\n        print(f'{median:.1f}')\n        break\n    if a_left > b_right:\n        high = cut_first - 1\n    else:\n        low = cut_first + 1", tests: [["1 3\n2", "2.0"], ["1 2\n3 4", "2.5"], ["-5 -1\n0 10 20", "0.0"]] }),
  p({ difficulty: "hard", id: "v5-kth-pair-sum", title: "Kth Smallest Cross-Array Sum", tags: ["lists", "sorting", "binary-search"], summary: "Select the kth smallest sum formed by choosing one value from each sorted array, counting duplicate index pairs.", input: "Two non-empty lines of sorted integers, then a one-based `k` no larger than the product of their lengths.", output: "The kth smallest pair sum.", solution: "first = list(map(int, input().split()))\nsecond = list(map(int, input().split()))\nk = int(input())\nlow = first[0] + second[0]\nhigh = first[-1] + second[-1]\nwhile low < high:\n    middle = (low + high) // 2\n    pairs = 0\n    right = len(second) - 1\n    for value in first:\n        while right >= 0 and value + second[right] > middle:\n            right -= 1\n        pairs += right + 1\n    if pairs >= k:\n        high = middle\n    else:\n        low = middle + 1\nprint(low)", tests: [["1 7 11\n2 4 6\n5", "11"], ["1 1\n1 2\n3", "3"], ["-3 0\n-2 4\n2", "-2"]] }),
  p({ difficulty: "hard", id: "v5-cargo-knapsack", title: "One-Trip Cargo Knapsack", tags: ["lists", "dynamic-programming", "optimization"], summary: "Choose each cargo item at most once to maximize value without exceeding a weight limit.", input: "`n capacity`, followed by `n` lines `weight value`. `n <= 200`, `capacity <= 20,000`, and all weights and values are positive.", output: "The maximum total value.", solution: "count, capacity = map(int, input().split())\nbest = [0] * (capacity + 1)\nfor _ in range(count):\n    weight, value = map(int, input().split())\n    for load in range(capacity, weight - 1, -1):\n        best[load] = max(best[load], best[load - weight] + value)\nprint(best[capacity])", tests: [["3 50\n10 60\n20 100\n30 120", "220"], ["3 5\n4 7\n2 4\n3 5", "9"], ["2 1\n2 10\n3 20", "0"]] }),
  p({ difficulty: "hard", id: "v5-balanced-partition-gap", title: "Balanced Partition Gap", tags: ["lists", "dynamic-programming", "sets"], summary: "Split positive values into two groups whose sums differ as little as possible.", input: "Space-separated positive integers whose total is at most 200,000.", output: "The minimum absolute difference between the two group sums.", solution: "values = list(map(int, input().split()))\ntotal = sum(values)\nreachable = 1\nfor value in values:\n    reachable |= reachable << value\nhalf = total // 2\nwhile not (reachable >> half) & 1:\n    half -= 1\nprint(total - 2 * half)", tests: [["1 6 11 5", "1"], ["3 1 4 2 2", "0"], ["8", "8"]] }),
  p({ difficulty: "hard", id: "v5-longest-bitonic-subsequence", title: "Longest Mountain Subsequence", tags: ["lists", "dynamic-programming", "sequences"], summary: "Find a longest subsequence that strictly rises and then strictly falls; either side may contain only the peak.", input: "A line of 1 to 2000 integers.", output: "The maximum mountain subsequence length.", solution: "values = list(map(int, input().split()))\nsize = len(values)\nrising = [1] * size\nfalling = [1] * size\nfor right in range(size):\n    for left in range(right):\n        if values[left] < values[right]:\n            rising[right] = max(rising[right], rising[left] + 1)\nfor left in range(size - 1, -1, -1):\n    for right in range(left + 1, size):\n        if values[right] < values[left]:\n            falling[left] = max(falling[left], falling[right] + 1)\nprint(max(rising[index] + falling[index] - 1 for index in range(size)))", tests: [["1 11 2 10 4 5 2 1", "6"], ["1 2 3 4", "4"], ["4 3 2 1", "4"]] }),
  p({ difficulty: "hard", id: "v5-maximum-product-slice", title: "Maximum Product Slice", tags: ["lists", "dynamic-programming", "subarrays"], summary: "Find the greatest product of a non-empty contiguous slice while accounting for sign flips.", input: "A line of 1 to 200,000 integers.", output: "The maximum contiguous product.", solution: "values = list(map(int, input().split()))\nmaximum = minimum = answer = values[0]\nfor value in values[1:]:\n    if value < 0:\n        maximum, minimum = minimum, maximum\n    maximum = max(value, maximum * value)\n    minimum = min(value, minimum * value)\n    answer = max(answer, maximum)\nprint(answer)", tests: [["2 3 -2 4", "6"], ["-2 0 -1", "0"], ["-2 3 -4", "24"]] }),
  p({ difficulty: "hard", id: "v5-circular-maximum-slice", title: "Maximum Circular Slice", tags: ["lists", "dynamic-programming", "circular-arrays"], summary: "Find the greatest sum of a non-empty contiguous slice in a circular array.", input: "A line of 1 to 200,000 integers.", output: "The maximum circular slice sum; an element may be used at most once.", solution: "values = list(map(int, input().split()))\ncurrent_max = best_max = values[0]\ncurrent_min = best_min = values[0]\nfor value in values[1:]:\n    current_max = max(value, current_max + value)\n    best_max = max(best_max, current_max)\n    current_min = min(value, current_min + value)\n    best_min = min(best_min, current_min)\nif best_max < 0:\n    print(best_max)\nelse:\n    print(max(best_max, sum(values) - best_min))", tests: [["5 -3 5", "10"], ["-3 -2 -5", "-2"], ["8 -1 -3 8", "16"]] }),
  p({ difficulty: "hard", id: "v5-histogram-rectangle", title: "Largest Histogram Rectangle", tags: ["lists", "stacks", "geometry"], summary: "Find the largest axis-aligned rectangle that fits beneath adjacent unit-width histogram bars.", input: "Space-separated nonnegative bar heights, with at least one bar.", output: "The maximum rectangle area.", solution: "heights = list(map(int, input().split())) + [0]\nstack = []\nbest = 0\nfor right, height in enumerate(heights):\n    start = right\n    while stack and stack[-1][1] > height:\n        index, previous = stack.pop()\n        best = max(best, previous * (right - index))\n        start = index\n    if not stack or stack[-1][1] < height:\n        stack.append((start, height))\nprint(best)", tests: [["2 1 5 6 2 3", "10"], ["2 4", "4"], ["1 1 1", "3"]] }),
  p({ difficulty: "hard", id: "v5-trapped-rain-volume", title: "Trapped Rain Volume", tags: ["lists", "two-pointers", "geometry"], summary: "Measure how many unit squares of rainwater remain between elevation bars.", input: "Space-separated nonnegative bar heights.", output: "The total trapped water volume.", solution: "heights = list(map(int, input().split()))\nleft, right = 0, len(heights) - 1\nleft_wall = right_wall = total = 0\nwhile left <= right:\n    if heights[left] <= heights[right]:\n        left_wall = max(left_wall, heights[left])\n        total += left_wall - heights[left]\n        left += 1\n    else:\n        right_wall = max(right_wall, heights[right])\n        total += right_wall - heights[right]\n        right -= 1\nprint(total)", tests: [["0 1 0 2 1 0 1 3 2 1 2 1", "6"], ["4 2 0 3 2 5", "9"], ["1 2 3", "0"]] }),
  p({ difficulty: "hard", id: "v5-circular-next-greater-distance", title: "Circular Next-Greater Distance", tags: ["lists", "stacks", "circular-arrays"], summary: "For every position, count forward circular steps to the first strictly greater value.", input: "A line of integers.", output: "One distance per position; use `0` where no greater value exists.", solution: "values = list(map(int, input().split()))\nsize = len(values)\nanswer = [0] * size\nstack = []\nfor index in range(2 * size):\n    position = index % size\n    while stack and values[stack[-1]] < values[position]:\n        previous = stack.pop()\n        answer[previous] = index - previous\n    if index < size:\n        stack.append(index)\nprint(*answer)", tests: [["1 2 1", "1 0 2"], ["5 4 3 2 1", "0 4 3 2 1"], ["2 2 2", "0 0 0"]] }),
  p({ difficulty: "hard", id: "v5-subarray-range-total", title: "Total of All Subarray Ranges", tags: ["lists", "stacks", "contributions"], summary: "Add `maximum - minimum` over every non-empty contiguous slice without enumerating the slices.", input: "A line of 1 to 200,000 integers; duplicate values are allowed.", output: "The exact sum of all slice ranges.", solution: "values = list(map(int, input().split()))\nsize = len(values)\nleft_min = [0] * size\nright_min = [0] * size\nleft_max = [0] * size\nright_max = [0] * size\nstack = []\nfor index, value in enumerate(values):\n    while stack and values[stack[-1]] >= value:\n        stack.pop()\n    left_min[index] = index - stack[-1] if stack else index + 1\n    stack.append(index)\nstack = []\nfor index in range(size - 1, -1, -1):\n    while stack and values[stack[-1]] > values[index]:\n        stack.pop()\n    right_min[index] = stack[-1] - index if stack else size - index\n    stack.append(index)\nstack = []\nfor index, value in enumerate(values):\n    while stack and values[stack[-1]] <= value:\n        stack.pop()\n    left_max[index] = index - stack[-1] if stack else index + 1\n    stack.append(index)\nstack = []\nfor index in range(size - 1, -1, -1):\n    while stack and values[stack[-1]] < values[index]:\n        stack.pop()\n    right_max[index] = stack[-1] - index if stack else size - index\n    stack.append(index)\ntotal = 0\nfor index, value in enumerate(values):\n    total += value * (left_max[index] * right_max[index] - left_min[index] * right_min[index])\nprint(total)", tests: [["1 2 3", "4"], ["1 3 3", "4"], ["4 -2 -3 4 1", "59"]] }),
  p({ difficulty: "hard", id: "v5-fewest-jumps-route", title: "Fewest Jumps with Route", tags: ["lists", "dynamic-programming", "paths"], summary: "Reach the final index using the fewest jumps and reconstruct the lexicographically smallest optimal index route.", input: "Space-separated nonnegative maximum jump lengths. The last index is reachable, and there are at most 2000 values.", output: "Print the minimum jump count, then the chosen zero-based indices on the next line. Among minimum-jump routes, choose the lexicographically smallest index sequence.", solution: "jumps = list(map(int, input().split()))\nsize = len(jumps)\ninfinity = size + 1\nbest = [infinity] * size\nnext_index = [-1] * size\nbest[-1] = 0\nfor index in range(size - 2, -1, -1):\n    stop = min(size, index + jumps[index] + 1)\n    for candidate in range(index + 1, stop):\n        score = best[candidate] + 1\n        if score < best[index]:\n            best[index] = score\n            next_index[index] = candidate\nroute = [0]\nwhile route[-1] != size - 1:\n    route.append(next_index[route[-1]])\nprint(best[0])\nprint(*route)", tests: [["2 3 1 1 4", "2\n0 1 4"], ["2 1 1", "1\n0 2"], ["1 1 1 1", "3\n0 1 2 3"]] }),
  p({ difficulty: "hard", id: "v5-first-circular-fuel-start", title: "Unique Circular Fuel Start", tags: ["lists", "greedy", "circular-arrays"], summary: "Find the one station from which a vehicle can complete a circular route without its fuel becoming negative.", input: "Fuel gained at each station, then travel costs to the next station. Lines have equal nonzero length and the test data guarantees exactly one feasible starting station.", output: "The zero-based feasible starting index.", solution: "fuel = list(map(int, input().split()))\ncost = list(map(int, input().split()))\nstart = 0\ntank = 0\nfor index in range(len(fuel)):\n    tank += fuel[index] - cost[index]\n    if tank < 0:\n        start = index + 1\n        tank = 0\nprint(start)", tests: [["1 2 3 4 5\n3 4 5 1 2", "3"], ["2 0 2\n1 2 1", "2"], ["1 2\n2 1", "1"]] }),
  p({ difficulty: "hard", id: "v5-weighted-interval-reward", title: "Weighted Interval Reward", tags: ["lists", "sorting", "dynamic-programming"], summary: "Choose compatible half-open jobs to earn the greatest total reward.", input: "A job count, then `start end reward` lines. Endpoints are integers, rewards are positive, and intervals ending when another starts are compatible.", output: "The maximum obtainable reward.", solution: "jobs = []\nfor _ in range(int(input())):\n    start, end, reward = map(int, input().split())\n    jobs.append((end, start, reward))\njobs.sort()\nends = [job[0] for job in jobs]\nbest = [0] * (len(jobs) + 1)\nfor index, (end, start, reward) in enumerate(jobs):\n    low, high = 0, index\n    while low < high:\n        middle = (low + high) // 2\n        if ends[middle] <= start:\n            low = middle + 1\n        else:\n            high = middle\n    compatible = low if low == index or ends[low] > start else low + 1\n    best[index + 1] = max(best[index], best[compatible] + reward)\nprint(best[-1])", tests: [["4\n1 3 5\n2 5 6\n4 6 5\n6 7 4", "14"], ["3\n0 10 20\n0 5 9\n5 10 12", "21"], ["1\n3 8 17", "17"]] }),
  p({ difficulty: "hard", id: "v5-minimum-interval-arrows", title: "Minimum Interval Arrows", tags: ["lists", "sorting", "greedy"], summary: "Burst every closed interval by placing as few point-arrows as possible.", input: "An interval count, followed by `start end` lines with `start <= end`.", output: "The minimum number of points whose union intersects every interval.", solution: "intervals = [tuple(map(int, input().split())) for _ in range(int(input()))]\nintervals.sort(key=lambda interval: interval[1])\narrows = 0\npoint = None\nfor start, end in intervals:\n    if point is None or start > point:\n        arrows += 1\n        point = end\nprint(arrows)", tests: [["4\n1 6\n2 8\n7 12\n10 16", "2"], ["3\n1 5\n2 4\n3 9", "1"], ["3\n0 0\n2 2\n4 4", "3"]] }),
  p({ difficulty: "hard", id: "v5-network-bridge-report", title: "Network Bridge Report", tags: ["lists", "graphs", "low-link"], summary: "Find every undirected edge whose removal disconnects a previously connected pair of nodes.", input: "`n m` with `n <= 200,000` and `m <= 400,000`, then `m` distinct simple undirected edges `u v` on nodes `0..n-1`.", output: "Bridges as `smaller-larger` in lexicographic numeric order, or `none`.", solution: "n, edge_count = map(int, input().split())\ngraph = [[] for _ in range(n)]\nfor _ in range(edge_count):\n    left, right = map(int, input().split())\n    graph[left].append(right)\n    graph[right].append(left)\ndiscovery = [-1] * n\nlow = [0] * n\nparent = [-1] * n\ntime = 0\nbridges = []\nfor root in range(n):\n    if discovery[root] != -1:\n        continue\n    discovery[root] = low[root] = time\n    time += 1\n    stack = [[root, 0]]\n    while stack:\n        node, next_edge = stack[-1]\n        if next_edge < len(graph[node]):\n            neighbor = graph[node][next_edge]\n            stack[-1][1] += 1\n            if discovery[neighbor] == -1:\n                parent[neighbor] = node\n                discovery[neighbor] = low[neighbor] = time\n                time += 1\n                stack.append([neighbor, 0])\n            elif neighbor != parent[node]:\n                low[node] = min(low[node], discovery[neighbor])\n        else:\n            stack.pop()\n            if parent[node] != -1:\n                previous = parent[node]\n                if low[node] > discovery[previous]:\n                    bridges.append((min(node, previous), max(node, previous)))\n                low[previous] = min(low[previous], low[node])\nbridges.sort()\nprint(' '.join(f'{left}-{right}' for left, right in bridges) if bridges else 'none')", tests: [["4 3\n0 1\n1 2\n2 3", "0-1 1-2 2-3"], ["4 4\n0 1\n1 2\n2 0\n2 3", "2-3"], ["3 3\n0 1\n1 2\n2 0", "none"]] }),
  p({ difficulty: "hard", id: "v5-bipartite-network-check", title: "Bipartite Network Check", tags: ["lists", "graphs", "coloring"], summary: "Decide whether every connected component of an undirected graph can be split into two sides with no internal edge.", input: "`n m` with `n <= 200,000` and `m <= 400,000`, followed by `m` simple undirected edges on nodes `0..n-1`.", output: "`yes` if the graph is bipartite, otherwise `no`.", solution: "n, edge_count = map(int, input().split())\ngraph = [[] for _ in range(n)]\nfor _ in range(edge_count):\n    left, right = map(int, input().split())\n    graph[left].append(right)\n    graph[right].append(left)\ncolor = [-1] * n\nvalid = True\nfor start in range(n):\n    if color[start] != -1:\n        continue\n    color[start] = 0\n    queue = [start]\n    head = 0\n    while head < len(queue):\n        node = queue[head]\n        head += 1\n        for neighbor in graph[node]:\n            if color[neighbor] == -1:\n                color[neighbor] = 1 - color[node]\n                queue.append(neighbor)\n            elif color[neighbor] == color[node]:\n                valid = False\nprint('yes' if valid else 'no')", tests: [["4 4\n0 1\n1 2\n2 3\n3 0", "yes"], ["3 3\n0 1\n1 2\n2 0", "no"], ["5 2\n0 1\n3 4", "yes"]] }),
  p({ difficulty: "hard", id: "v5-strong-component-count", title: "Strong Component Count", tags: ["lists", "graphs", "directed-graphs"], summary: "Count maximal groups of directed-graph nodes that can all reach one another.", input: "`n m` with `n <= 200,000` and `m <= 400,000`, followed by `m` directed edges `from to` on nodes `0..n-1`.", output: "The number of strongly connected components.", solution: "n, edge_count = map(int, input().split())\ngraph = [[] for _ in range(n)]\nreverse = [[] for _ in range(n)]\nfor _ in range(edge_count):\n    left, right = map(int, input().split())\n    graph[left].append(right)\n    reverse[right].append(left)\nvisited = [False] * n\norder = []\nfor start in range(n):\n    if visited[start]:\n        continue\n    visited[start] = True\n    stack = [[start, 0]]\n    while stack:\n        node, edge = stack[-1]\n        if edge < len(graph[node]):\n            neighbor = graph[node][edge]\n            stack[-1][1] += 1\n            if not visited[neighbor]:\n                visited[neighbor] = True\n                stack.append([neighbor, 0])\n        else:\n            order.append(node)\n            stack.pop()\nassigned = [False] * n\ncomponents = 0\nfor start in reversed(order):\n    if assigned[start]:\n        continue\n    components += 1\n    assigned[start] = True\n    stack = [start]\n    while stack:\n        node = stack.pop()\n        for neighbor in reverse[node]:\n            if not assigned[neighbor]:\n                assigned[neighbor] = True\n                stack.append(neighbor)\nprint(components)", tests: [["5 5\n0 1\n1 0\n1 2\n2 3\n3 2", "3"], ["3 3\n0 1\n1 2\n2 0", "1"], ["4 3\n0 1\n1 2\n2 3", "4"]] }),
  p({ difficulty: "hard", id: "v5-minimum-spanning-cost", title: "Minimum Spanning Cost", tags: ["lists", "sorting", "graphs"], summary: "Connect every node of a weighted undirected graph for the least total edge cost.", input: "`n m`, then `m` edges `u v weight`. The graph is connected and weights may be negative.", output: "The total weight of a minimum spanning tree.", solution: "n, edge_count = map(int, input().split())\nedges = []\nfor _ in range(edge_count):\n    left, right, weight = map(int, input().split())\n    edges.append((weight, left, right))\nedges.sort()\nparent = list(range(n))\nsize = [1] * n\ntotal = 0\nchosen = 0\nfor weight, left, right in edges:\n    root_left = left\n    while parent[root_left] != root_left:\n        parent[root_left] = parent[parent[root_left]]\n        root_left = parent[root_left]\n    root_right = right\n    while parent[root_right] != root_right:\n        parent[root_right] = parent[parent[root_right]]\n        root_right = parent[root_right]\n    if root_left == root_right:\n        continue\n    if size[root_left] < size[root_right]:\n        root_left, root_right = root_right, root_left\n    parent[root_right] = root_left\n    size[root_left] += size[root_right]\n    total += weight\n    chosen += 1\n    if chosen == n - 1:\n        break\nprint(total)", tests: [["4 5\n0 1 1\n1 2 2\n2 3 3\n0 3 10\n0 2 4", "6"], ["3 3\n0 1 5\n1 2 1\n0 2 2", "3"], ["2 1\n0 1 -4", "-4"]] }),
  p({ difficulty: "hard", id: "v5-edge-budget-route", title: "Route with an Edge Budget", tags: ["lists", "graphs", "dynamic-programming"], summary: "Find the cheapest directed route when at most `k` edges may be used.", input: "`n m`, then `m` directed edges `u v cost`, then `start end k`. Costs are nonnegative, nodes are `0..n-1`, and `n*m*k <= 20,000,000`.", output: "The minimum cost using at most `k` edges, or `-1` if no such route exists.", solution: "n, edge_count = map(int, input().split())\nedges = [tuple(map(int, input().split())) for _ in range(edge_count)]\nstart, end, limit = map(int, input().split())\ninfinity = 10 ** 30\nbest = [infinity] * n\nbest[start] = 0\nfor _ in range(limit):\n    updated = best[:]\n    for left, right, cost in edges:\n        if best[left] != infinity:\n            updated[right] = min(updated[right], best[left] + cost)\n    best = updated\nprint(-1 if best[end] == infinity else best[end])", tests: [["4 4\n0 1 5\n1 3 5\n0 2 2\n2 3 20\n0 3 2", "10"], ["3 3\n0 1 2\n1 2 2\n0 2 10\n0 2 1", "10"], ["3 1\n0 1 4\n0 2 5", "-1"]] }),
  p({ difficulty: "hard", id: "v5-knight-obstacle-route", title: "Knight Route Through Obstacles", tags: ["lists", "grids", "graphs"], summary: "Find a chess knight's shortest route from `S` to `E` while avoiding blocked squares.", input: "`rows columns`, followed by a grid containing one `S`, one `E`, dots, and `#` obstacles, with at most 200,000 cells.", output: "The minimum number of knight moves, or `-1` if unreachable.", solution: "rows, columns = map(int, input().split())\ngrid = [input() for _ in range(rows)]\nqueue = []\nseen = set()\nfor row in range(rows):\n    for column in range(columns):\n        if grid[row][column] == 'S':\n            queue.append((row, column, 0))\n            seen.add((row, column))\nhead = 0\nanswer = -1\nmoves = ((1, 2), (2, 1), (-1, 2), (-2, 1), (1, -2), (2, -1), (-1, -2), (-2, -1))\nwhile head < len(queue):\n    row, column, distance = queue[head]\n    head += 1\n    if grid[row][column] == 'E':\n        answer = distance\n        break\n    for row_change, column_change in moves:\n        next_row = row + row_change\n        next_column = column + column_change\n        if 0 <= next_row < rows and 0 <= next_column < columns and grid[next_row][next_column] != '#' and (next_row, next_column) not in seen:\n            seen.add((next_row, next_column))\n            queue.append((next_row, next_column, distance + 1))\nprint(answer)", tests: [["4 4\nS...\n....\n....\n...E", "2"], ["3 3\nS..\n...\n..E", "4"], ["2 3\nS..\n..E", "1"]] }),
  p({ difficulty: "hard", id: "v5-widest-grid-path", title: "Widest Grid Path", tags: ["lists", "grids", "optimization"], summary: "Cross a height grid while maximizing the minimum cell value encountered.", input: "`rows columns`, then integer rows, with at most 2500 cells and `|value| <= 10^18`. Move four-directionally from the top-left to the bottom-right; both endpoints count.", output: "The greatest achievable bottleneck value.", solution: "rows, columns = map(int, input().split())\ngrid = [list(map(int, input().split())) for _ in range(rows)]\nbest = [[-10 ** 30] * columns for _ in range(rows)]\nused = [[False] * columns for _ in range(rows)]\nbest[0][0] = grid[0][0]\nfor _ in range(rows * columns):\n    chosen_row = chosen_column = -1\n    chosen_value = -10 ** 30\n    for row in range(rows):\n        for column in range(columns):\n            if not used[row][column] and best[row][column] > chosen_value:\n                chosen_value = best[row][column]\n                chosen_row, chosen_column = row, column\n    if chosen_row == -1 or (chosen_row == rows - 1 and chosen_column == columns - 1):\n        break\n    used[chosen_row][chosen_column] = True\n    for row_change, column_change in ((1, 0), (-1, 0), (0, 1), (0, -1)):\n        next_row = chosen_row + row_change\n        next_column = chosen_column + column_change\n        if 0 <= next_row < rows and 0 <= next_column < columns and not used[next_row][next_column]:\n            candidate = min(chosen_value, grid[next_row][next_column])\n            best[next_row][next_column] = max(best[next_row][next_column], candidate)\nprint(best[-1][-1])", tests: [["3 3\n5 4 5\n1 2 6\n7 4 6", "4"], ["2 2\n8 1\n7 6", "6"], ["1 3\n3 9 2", "2"]] }),
  p({ difficulty: "hard", id: "v5-grid-word-trail", title: "Grid Word Trail", tags: ["lists", "grids", "backtracking"], summary: "Determine whether a word can be traced through orthogonally adjacent cells without reusing a cell.", input: "`rows columns`, at most 2500 grid letters without spaces, then a non-empty word of at most 12 letters.", output: "`yes` if some trail spells the word, otherwise `no`.", solution: "rows, columns = map(int, input().split())\ngrid = [input() for _ in range(rows)]\nword = input()\nfound = False\nstack = []\nfor row in range(rows):\n    for column in range(columns):\n        if grid[row][column] == word[0]:\n            stack.append((row, column, 0, frozenset([(row, column)])))\nwhile stack and not found:\n    row, column, index, used = stack.pop()\n    if index == len(word) - 1:\n        found = True\n        break\n    for row_change, column_change in ((1, 0), (-1, 0), (0, 1), (0, -1)):\n        next_row = row + row_change\n        next_column = column + column_change\n        if 0 <= next_row < rows and 0 <= next_column < columns and (next_row, next_column) not in used and grid[next_row][next_column] == word[index + 1]:\n            stack.append((next_row, next_column, index + 1, used | {(next_row, next_column)}))\nprint('yes' if found else 'no')", tests: [["3 4\nABCE\nSFCS\nADEE\nABCCED", "yes"], ["3 4\nABCE\nSFCS\nADEE\nSEE", "yes"], ["3 4\nABCE\nSFCS\nADEE\nABCB", "no"]] }),
  p({ difficulty: "hard", id: "v5-largest-one-square", title: "Largest All-One Square", tags: ["lists", "grids", "dynamic-programming"], summary: "Find the area of the largest square containing only `1` cells in a binary grid.", input: "`rows columns`, followed by binary grid rows without spaces, with at most 200,000 cells.", output: "The square's area, or `0` if the grid contains no `1`.", solution: "rows, columns = map(int, input().split())\nprevious = [0] * (columns + 1)\nbest = 0\nfor _ in range(rows):\n    line = input()\n    current = [0] * (columns + 1)\n    for column, cell in enumerate(line, 1):\n        if cell == '1':\n            current[column] = 1 + min(previous[column], current[column - 1], previous[column - 1])\n            best = max(best, current[column])\n    previous = current\nprint(best * best)", tests: [["4 5\n10100\n10111\n11111\n10010", "4"], ["2 3\n111\n111", "4"], ["1 4\n0000", "0"]] }),
  p({ difficulty: "hard", id: "v5-nonrepeating-column-fall", title: "Nonrepeating-Column Falling Path", tags: ["lists", "grids", "dynamic-programming"], summary: "Choose one value per matrix row for minimum sum without choosing the same column in consecutive rows.", input: "`rows columns`, then integer rows, with at most 200,000 cells. If there is more than one row, there are at least two columns.", output: "The minimum valid path sum.", solution: "rows, columns = map(int, input().split())\nprevious = list(map(int, input().split()))\nfor _ in range(1, rows):\n    row = list(map(int, input().split()))\n    first = min(range(columns), key=lambda column: previous[column])\n    second_value = min(previous[column] for column in range(columns) if column != first)\n    current = []\n    for column in range(columns):\n        current.append(row[column] + (second_value if column == first else previous[first]))\n    previous = current\nprint(min(previous))", tests: [["3 3\n1 2 3\n4 5 6\n7 8 9", "13"], ["2 2\n-1 2\n3 4", "3"], ["1 3\n5 -2 7", "-2"]] }),
  p({ difficulty: "hard", id: "v5-matrix-chain-cost", title: "Matrix Chain Multiplication Cost", tags: ["lists", "dynamic-programming", "intervals"], summary: "Parenthesize a chain of compatible matrix products to minimize scalar multiplications.", input: "Space-separated positive dimensions `d0 d1 ... dn`, describing at most 200 matrices `d0xd1` through `d(n-1)xdn`.", output: "The minimum scalar multiplication count; a single matrix costs 0.", solution: "dimensions = list(map(int, input().split()))\ncount = len(dimensions) - 1\nbest = [[0] * count for _ in range(count)]\nfor length in range(2, count + 1):\n    for left in range(count - length + 1):\n        right = left + length - 1\n        best[left][right] = min(best[left][split] + best[split + 1][right] + dimensions[left] * dimensions[split + 1] * dimensions[right + 1] for split in range(left, right))\nprint(best[0][count - 1])", tests: [["40 20 30 10 30", "26000"], ["10 20 30", "6000"], ["10 20", "0"]] }),
  p({ difficulty: "hard", id: "v5-burst-balloon-score", title: "Burst Balloon Score", tags: ["lists", "dynamic-programming", "intervals"], summary: "Choose a balloon-bursting order to maximize coins, where each burst scores its value times its current neighbors.", input: "Between 1 and 200 positive balloon values. Missing neighbors beyond the ends have value 1.", output: "The maximum total score.", solution: "values = [1] + list(map(int, input().split())) + [1]\nsize = len(values)\nbest = [[0] * size for _ in range(size)]\nfor gap in range(2, size):\n    for left in range(size - gap):\n        right = left + gap\n        best[left][right] = max(best[left][last] + best[last][right] + values[left] * values[last] * values[right] for last in range(left + 1, right))\nprint(best[0][-1])", tests: [["3 1 5 8", "167"], ["1 5", "10"], ["7", "7"]] }),
  p({ difficulty: "hard", id: "v5-polygon-triangulation-score", title: "Minimum Polygon Triangulation Score", tags: ["lists", "dynamic-programming", "geometry"], summary: "Triangulate a convex weighted polygon while minimizing the sum of the three-vertex products of its triangles.", input: "Between 3 and 200 positive vertex weights in clockwise order.", output: "The minimum triangulation score.", solution: "weights = list(map(int, input().split()))\nsize = len(weights)\nbest = [[0] * size for _ in range(size)]\nfor gap in range(2, size):\n    for left in range(size - gap):\n        right = left + gap\n        best[left][right] = min(best[left][middle] + best[middle][right] + weights[left] * weights[middle] * weights[right] for middle in range(left + 1, right))\nprint(best[0][-1])", tests: [["1 3 1 4 1 5", "13"], ["3 7 4 5", "144"], ["2 3 4", "24"]] }),
  p({ difficulty: "hard", id: "v5-dungeon-starting-health", title: "Dungeon Starting Health", tags: ["lists", "grids", "dynamic-programming"], summary: "Find the least health needed to cross a dungeon without health ever falling below 1.", input: "`rows columns`, followed by integer room effects, with at most 200,000 cells and `|effect| <= 10^18`. Start top-left, finish bottom-right, and move only right or down.", output: "The minimum positive starting health.", solution: "rows, columns = map(int, input().split())\ngrid = [list(map(int, input().split())) for _ in range(rows)]\nneeded = [[10 ** 30] * (columns + 1) for _ in range(rows + 1)]\nneeded[rows][columns - 1] = 1\nneeded[rows - 1][columns] = 1\nfor row in range(rows - 1, -1, -1):\n    for column in range(columns - 1, -1, -1):\n        after = min(needed[row + 1][column], needed[row][column + 1])\n        needed[row][column] = max(1, after - grid[row][column])\nprint(needed[0][0])", tests: [["3 3\n-2 -3 3\n-5 -10 1\n10 30 -5", "7"], ["1 1\n5", "1"], ["1 2\n-5 -10", "16"]] }),
  p({ difficulty: "hard", id: "v5-n-queens-arrangements", title: "N-Queens Arrangement Count", tags: ["lists", "backtracking", "bitmasks"], summary: "Count ways to place `n` queens so that no two share a row, column, or diagonal.", input: "One integer `n` with `1 <= n <= 13`.", output: "The number of distinct arrangements on a labeled board.", solution: "n = int(input())\nfull = (1 << n) - 1\ncolumns = [0] * (n + 1)\nleft_diagonals = [0] * (n + 1)\nright_diagonals = [0] * (n + 1)\navailable = [0] * n\navailable[0] = full\nrow = 0\ncount = 0\nwhile row >= 0:\n    if available[row]:\n        bit = available[row] & -available[row]\n        available[row] -= bit\n        if row == n - 1:\n            count += 1\n        else:\n            columns[row + 1] = columns[row] | bit\n            left_diagonals[row + 1] = ((left_diagonals[row] | bit) << 1) & full\n            right_diagonals[row + 1] = (right_diagonals[row] | bit) >> 1\n            row += 1\n            available[row] = full & ~(columns[row] | left_diagonals[row] | right_diagonals[row])\n    else:\n        row -= 1\nprint(count)", tests: [["4", "2"], ["1", "1"], ["8", "92"]] }),
];

const dictionaryProblems: Problem[] = [
  p({ difficulty: "hard", id: "v5-exactly-k-distinct-slices", title: "Slices with Exactly K Distinct Values", tags: ["dictionaries", "sliding-window", "counting"], summary: "Count contiguous slices containing exactly `k` different values in linear time.", input: "Space-separated integers, then a positive integer `k`.", output: "The number of index-distinct contiguous slices with exactly `k` distinct values.", solution: "values = list(map(int, input().split()))\nk = int(input())\nresults = []\nfor limit in (k, k - 1):\n    counts = {}\n    left = 0\n    total = 0\n    for right, value in enumerate(values):\n        counts[value] = counts.get(value, 0) + 1\n        while len(counts) > limit:\n            outgoing = values[left]\n            counts[outgoing] -= 1\n            if counts[outgoing] == 0:\n                del counts[outgoing]\n            left += 1\n        total += right - left + 1\n    results.append(total)\nprint(results[0] - results[1])", tests: [["1 2 1 2 3\n2", "7"], ["1 2 1 3 4\n3", "3"], ["1 1 1\n1", "6"]] }),
  p({ difficulty: "hard", id: "v5-equal-tricolor-span", title: "Longest Equal Tricolor Span", tags: ["dictionaries", "prefix-state", "sequences"], summary: "Find the longest contiguous span containing equal counts of 0, 1, and 2.", input: "A non-empty line containing only space-separated `0`, `1`, and `2` values.", output: "The maximum valid span length, or `0` if no non-empty span qualifies.", solution: "values = list(map(int, input().split()))\ncounts = [0, 0, 0]\nfirst_seen = {(0, 0): -1}\nbest = 0\nfor index, value in enumerate(values):\n    counts[value] += 1\n    state = (counts[1] - counts[0], counts[2] - counts[0])\n    if state in first_seen:\n        best = max(best, index - first_seen[state])\n    else:\n        first_seen[state] = index\nprint(best)", tests: [["0 1 2", "3"], ["0 0 1 1 2 2", "6"], ["0 1 0 2", "3"]] }),
  p({ difficulty: "hard", id: "v5-ratio-equation-queries", title: "Ratio Equation Queries", tags: ["dictionaries", "graphs", "weighted-relations"], summary: "Infer requested variable ratios from a consistent network of multiplicative equations.", input: "An equation count, `a b ratio` lines meaning `a/b=ratio`, a query count, then `a b` queries. Ratios are positive decimals.", output: "One result per query to five decimal places, or `-1.00000` when either variable is unknown or no relation connects them.", solution: "equation_count = int(input())\ngraph = {}\nfor _ in range(equation_count):\n    left, right, ratio_text = input().split()\n    ratio = float(ratio_text)\n    graph.setdefault(left, []).append((right, ratio))\n    graph.setdefault(right, []).append((left, 1 / ratio))\nfor _ in range(int(input())):\n    start, end = input().split()\n    answer = None\n    if start in graph and end in graph:\n        stack = [(start, 1.0)]\n        seen = {start}\n        while stack:\n            node, value = stack.pop()\n            if node == end:\n                answer = value\n                break\n            for neighbor, multiplier in graph[node]:\n                if neighbor not in seen:\n                    seen.add(neighbor)\n                    stack.append((neighbor, value * multiplier))\n    print(f'{answer if answer is not None else -1:.5f}')", tests: [["2\na b 2\nb c 3\n3\na c\nc a\na x", "6.00000\n0.16667\n-1.00000"], ["1\nx y 4\n3\nx x\ny x\nz z", "1.00000\n0.25000\n-1.00000"], ["2\nusd eur 0.9\neur gbp 0.8\n2\nusd gbp\ngbp usd", "0.72000\n1.38889"]] }),
  p({ difficulty: "hard", id: "v5-lexical-ticket-itinerary", title: "Lexical Ticket Itinerary", tags: ["dictionaries", "graphs", "euler-trail"], summary: "Reconstruct an itinerary beginning at `JFK` that uses every directed ticket exactly once.", input: "A ticket count followed by `origin destination` lines. At least one complete itinerary from `JFK` is guaranteed.", output: "The lexicographically smallest full airport sequence, comparing routes airport by airport.", solution: "tickets = {}\nfor _ in range(int(input())):\n    origin, destination = input().split()\n    tickets.setdefault(origin, []).append(destination)\nfor origin in tickets:\n    tickets[origin].sort(reverse=True)\nstack = ['JFK']\nroute = []\nwhile stack:\n    airport = stack[-1]\n    if tickets.get(airport):\n        stack.append(tickets[airport].pop())\n    else:\n        route.append(stack.pop())\nprint(*reversed(route))", tests: [["4\nJFK SFO\nJFK ATL\nSFO ATL\nATL JFK", "JFK ATL JFK SFO ATL"], ["3\nJFK KUL\nJFK NRT\nNRT JFK", "JFK NRT JFK KUL"], ["2\nJFK A\nA JFK", "JFK A JFK"]] }),
  p({ difficulty: "hard", id: "v5-sparse-polynomial-product", title: "Sparse Polynomial Product", tags: ["dictionaries", "algebra", "aggregation"], summary: "Multiply two sparse integer polynomials by combining terms with equal exponents.", input: "Two lines of space-separated `exponent:coefficient` terms with unique nonnegative exponents, or `zero`. Coefficients are nonzero integers.", output: "Nonzero `exponent:coefficient` terms in decreasing exponent order, or `zero`.", solution: "lines = [input().strip(), input().strip()]\npolynomials = []\nfor line in lines:\n    terms = {}\n    if line != 'zero':\n        for item in line.split():\n            exponent, coefficient = map(int, item.split(':'))\n            terms[exponent] = coefficient\n    polynomials.append(terms)\nproduct = {}\nfor first_exponent, first_coefficient in polynomials[0].items():\n    for second_exponent, second_coefficient in polynomials[1].items():\n        exponent = first_exponent + second_exponent\n        product[exponent] = product.get(exponent, 0) + first_coefficient * second_coefficient\nparts = [f'{exponent}:{product[exponent]}' for exponent in sorted(product, reverse=True) if product[exponent] != 0]\nprint(' '.join(parts) if parts else 'zero')", tests: [["0:1 1:2\n0:3 2:4", "3:8 2:4 1:6 0:3"], ["1:1 0:1\n1:1 0:-1", "2:1 0:-1"], ["zero\n4:9", "zero"]] }),
];

const functionProblems: Problem[] = [
  p({ difficulty: "hard", id: "v5-extended-euclid-coefficients", title: "Extended Euclid Coefficients", tags: ["functions", "recursion", "number-theory"], summary: "Use the recursive extended Euclidean algorithm to produce a greatest common divisor and Bezout coefficients.", input: "Two integers `a b` with `a > 0` and `b >= 0`.", output: "Three integers `g x y` from the standard recursive algorithm such that `g=gcd(a,b)` and `a*x+b*y=g`.", solution: "def extended_gcd(a, b):\n    if b == 0:\n        return a, 1, 0\n    gcd, next_x, next_y = extended_gcd(b, a % b)\n    return gcd, next_y, next_x - (a // b) * next_y\n\na, b = map(int, input().split())\nprint(*extended_gcd(a, b))", tests: [["240 46", "2 -9 47"], ["99 78", "3 -11 14"], ["7 0", "7 1 0"]] }),
  p({ difficulty: "hard", id: "v5-kth-tower-move", title: "Kth Tower of Hanoi Move", tags: ["functions", "recursion", "divide-and-conquer"], summary: "Identify one move deep inside the optimal Tower of Hanoi solution without generating earlier moves.", input: "Two integers `n k` with `1 <= n <= 60` and `1 <= k < 2^n`. Move all disks from peg `A` to peg `C` using peg `B`.", output: "The source and destination peg of the kth move, separated by a space.", solution: "def kth_move(disks, move, source, target, spare):\n    middle = 1 << (disks - 1)\n    if move == middle:\n        return source, target\n    if move < middle:\n        return kth_move(disks - 1, move, source, spare, target)\n    return kth_move(disks - 1, move - middle, spare, target, source)\n\ndisks, move = map(int, input().split())\nprint(*kth_move(disks, move, 'A', 'C', 'B'))", tests: [["3 5", "B A"], ["4 8", "A C"], ["1 1", "A C"]] }),
  p({ difficulty: "hard", id: "v5-recursive-expression-parser", title: "Recursive Arithmetic Parser", tags: ["functions", "recursion", "parsing"], summary: "Evaluate an arithmetic expression by writing mutually layered recursive parsing functions.", input: "One valid expression containing integers, spaces, `+`, `-`, `*`, parentheses, and unary minus.", output: "The exact integer result; multiplication has higher precedence than addition and subtraction.", solution: "def evaluate(text):\n    text = text.replace(' ', '')\n    index = 0\n\n    def expression():\n        nonlocal index\n        value = term()\n        while index < len(text) and text[index] in '+-':\n            operator = text[index]\n            index += 1\n            other = term()\n            value = value + other if operator == '+' else value - other\n        return value\n\n    def term():\n        nonlocal index\n        value = factor()\n        while index < len(text) and text[index] == '*':\n            index += 1\n            value *= factor()\n        return value\n\n    def factor():\n        nonlocal index\n        if text[index] == '-':\n            index += 1\n            return -factor()\n        if text[index] == '(':\n            index += 1\n            value = expression()\n            index += 1\n            return value\n        start = index\n        while index < len(text) and text[index].isdigit():\n            index += 1\n        return int(text[start:index])\n\n    return expression()\n\nprint(evaluate(input()))", tests: [["2*(3+4)-5", "9"], ["-(2+3)*4", "-20"], ["10 + 2 * (8 - 3 * 2)", "14"]] }),
  p({ difficulty: "hard", id: "v5-no-equal-neighbor-digits", title: "Digit-DP Neighbor Rule", tags: ["functions", "recursion", "digit-dp"], summary: "Count integers whose ordinary decimal representation has no equal adjacent digits.", input: "One integer `n` with `0 <= n <= 10^18`.", output: "The count of valid integers in the inclusive range `0..n`; the representation `0` is valid.", solution: "digits = list(map(int, str(int(input()))))\nmemo = {}\n\ndef count(position, previous, started, tight):\n    if position == len(digits):\n        return 1\n    key = (position, previous, started, tight)\n    if key in memo:\n        return memo[key]\n    limit = digits[position] if tight else 9\n    total = 0\n    for digit in range(limit + 1):\n        next_tight = tight and digit == limit\n        if not started and digit == 0:\n            total += count(position + 1, -1, False, next_tight)\n        elif not started or digit != previous:\n            total += count(position + 1, digit, True, next_tight)\n    memo[key] = total\n    return total\n\nprint(count(0, -1, False, True))", tests: [["20", "20"], ["9", "10"], ["100", "91"]] }),
  p({ difficulty: "hard", id: "v5-recursive-tree-diameter", title: "Recursive Weighted Tree Diameter", tags: ["functions", "recursion", "graphs"], summary: "Use postorder recursion to find the longest weighted path between any two nodes of a tree.", input: "A node count `n <= 800`, followed by `n-1` lines `u v positive_weight` on nodes `0..n-1`.", output: "The maximum path weight; for a one-node tree output 0.", solution: "def tree_diameter(graph):\n    diameter = 0\n\n    def visit(node, parent):\n        nonlocal diameter\n        longest = second = 0\n        for neighbor, weight in graph[node]:\n            if neighbor == parent:\n                continue\n            branch = visit(neighbor, node) + weight\n            if branch > longest:\n                longest, second = branch, longest\n            elif branch > second:\n                second = branch\n        diameter = max(diameter, longest + second)\n        return longest\n\n    visit(0, -1)\n    return diameter\n\nn = int(input())\ngraph = [[] for _ in range(n)]\nfor _ in range(n - 1):\n    left, right, weight = map(int, input().split())\n    graph[left].append((right, weight))\n    graph[right].append((left, weight))\nprint(tree_diameter(graph))", tests: [["5\n0 1 3\n1 2 4\n1 3 2\n3 4 6", "12"], ["1", "0"], ["3\n0 1 5\n1 2 7", "12"]] }),
  p({ difficulty: "hard", id: "v5-divide-closest-points", title: "Divide-and-Conquer Closest Points", tags: ["functions", "recursion", "geometry"], summary: "Find the squared distance between the closest pair of distinct planar points in subquadratic time.", input: "A count `2 <= n <= 50,000`, followed by `x y` integer coordinates. All points are distinct.", output: "The minimum squared Euclidean distance.", solution: "def closest(points):\n    if len(points) <= 3:\n        best = 10 ** 40\n        for first in range(len(points)):\n            for second in range(first + 1, len(points)):\n                dx = points[first][0] - points[second][0]\n                dy = points[first][1] - points[second][1]\n                best = min(best, dx * dx + dy * dy)\n        return best, sorted(points, key=lambda point: point[1])\n    middle = len(points) // 2\n    dividing_x = points[middle][0]\n    left_best, left_y = closest(points[:middle])\n    right_best, right_y = closest(points[middle:])\n    best = min(left_best, right_best)\n    merged = []\n    left = right = 0\n    while left < len(left_y) and right < len(right_y):\n        if left_y[left][1] <= right_y[right][1]:\n            merged.append(left_y[left]); left += 1\n        else:\n            merged.append(right_y[right]); right += 1\n    merged += left_y[left:] + right_y[right:]\n    strip = [point for point in merged if (point[0] - dividing_x) ** 2 < best]\n    for first in range(len(strip)):\n        second = first + 1\n        while second < len(strip) and (strip[second][1] - strip[first][1]) ** 2 < best:\n            dx = strip[first][0] - strip[second][0]\n            dy = strip[first][1] - strip[second][1]\n            best = min(best, dx * dx + dy * dy)\n            second += 1\n    return best, merged\n\npoints = [tuple(map(int, input().split())) for _ in range(int(input()))]\npoints.sort()\nprint(closest(points)[0])", tests: [["3\n0 0\n3 4\n7 7", "25"], ["4\n0 0\n5 5\n2 1\n9 9", "5"], ["3\n-1 -1\n2 3\n0 0", "2"]] }),
  p({ difficulty: "hard", id: "v5-optimal-end-picking", title: "Optimal End-Picking Game", tags: ["functions", "recursion", "game-theory"], summary: "Compute the largest total the first player can guarantee when players alternately take either end value.", input: "Between 1 and 500 space-separated nonnegative integers; both players play optimally.", output: "The maximum total collected by the first player.", solution: "values = list(map(int, input().split()))\nmemo = {}\n\ndef advantage(left, right):\n    if left == right:\n        return values[left]\n    key = (left, right)\n    if key not in memo:\n        memo[key] = max(values[left] - advantage(left + 1, right), values[right] - advantage(left, right - 1))\n    return memo[key]\n\ndifference = advantage(0, len(values) - 1)\nprint((sum(values) + difference) // 2)", tests: [["8 15 3 7", "22"], ["2 2 2", "4"], ["5 3 7 10", "15"]] }),
  p({ difficulty: "hard", id: "v5-quadtree-compression", title: "Recursive Quadtree Compression", tags: ["functions", "recursion", "grids"], summary: "Compress a power-of-two binary image into a preorder quadtree encoding.", input: "A power-of-two size `n`, followed by `n` binary rows. `n <= 1024`.", output: "A uniform region is `0` or `1`; otherwise output `(NWNE SWSE)` with no spaces, specifically `(` followed by northwest, northeast, southwest, southeast encodings and `)`.", solution: "size = int(input())\ngrid = [input() for _ in range(size)]\n\ndef encode(top, left, width):\n    first = grid[top][left]\n    uniform = True\n    for row in range(top, top + width):\n        for column in range(left, left + width):\n            if grid[row][column] != first:\n                uniform = False\n                break\n        if not uniform:\n            break\n    if uniform:\n        return first\n    half = width // 2\n    return '(' + encode(top, left, half) + encode(top, left + half, half) + encode(top + half, left, half) + encode(top + half, left + half, half) + ')'\n\nprint(encode(0, 0, size))", tests: [["2\n01\n10", "(0110)"], ["4\n1111\n1111\n1111\n1111", "1"], ["4\n0011\n0011\n1100\n1100", "(0110)"]] }),
  p({ difficulty: "hard", id: "v5-boolean-parenthesization", title: "Boolean Parenthesization Count", tags: ["functions", "recursion", "dynamic-programming"], summary: "Count full parenthesizations of a boolean expression that evaluate to true.", input: "An expression of at most 120 symbols, alternating `T` or `F` with `&`, `|`, or `^`. Operators have no preset precedence.", output: "The exact number of parenthesizations evaluating to true.", solution: "expression = input().strip()\nsymbols = expression[::2]\noperators = expression[1::2]\nmemo = {}\n\ndef ways(left, right):\n    if left == right:\n        return (1, 0) if symbols[left] == 'T' else (0, 1)\n    key = (left, right)\n    if key in memo:\n        return memo[key]\n    true_total = false_total = 0\n    for split in range(left, right):\n        left_true, left_false = ways(left, split)\n        right_true, right_false = ways(split + 1, right)\n        all_ways = (left_true + left_false) * (right_true + right_false)\n        operator = operators[split]\n        if operator == '&':\n            true_ways = left_true * right_true\n        elif operator == '|':\n            true_ways = all_ways - left_false * right_false\n        else:\n            true_ways = left_true * right_false + left_false * right_true\n        true_total += true_ways\n        false_total += all_ways - true_ways\n    memo[key] = true_total, false_total\n    return memo[key]\n\nprint(ways(0, len(symbols) - 1)[0])", tests: [["T|F&T^T", "2"], ["T^T^F", "0"], ["T&T|F", "2"]] }),
  p({ difficulty: "hard", id: "v5-karatsuba-product", title: "Karatsuba Product Function", tags: ["functions", "recursion", "divide-and-conquer"], summary: "Multiply large nonnegative integers with recursive Karatsuba splitting.", input: "Two nonnegative decimal integers, each containing at most 2000 digits.", output: "Their exact product without leading zeroes.", solution: "def karatsuba(left, right):\n    if left < 1_000_000 or right < 1_000_000:\n        return left * right\n    digits = max(len(str(left)), len(str(right)))\n    half = digits // 2\n    power = 10 ** half\n    left_high, left_low = divmod(left, power)\n    right_high, right_low = divmod(right, power)\n    low_product = karatsuba(left_low, right_low)\n    high_product = karatsuba(left_high, right_high)\n    cross = karatsuba(left_low + left_high, right_low + right_high) - low_product - high_product\n    return high_product * power * power + cross * power + low_product\n\nfirst = int(input())\nsecond = int(input())\nprint(karatsuba(first, second))", tests: [["1234\n5678", "7006652"], ["0\n987654321", "0"], ["99999\n99999", "9999800001"]] }),
];

const moduleProblems: Problem[] = [
  p({ difficulty: "hard", id: "v5-json-leaf-paths", title: "JSON Leaf Paths", tags: ["modules", "functions", "json", "recursion"], summary: "Parse JSON and flatten every scalar leaf into an unambiguous path.", input: "One JSON object on a line. Object keys contain only letters, digits, and underscores; arrays and nested objects may appear.", output: "Space-separated `path=value` leaves sorted by path. Use dots for object keys, `[index]` for arrays, and compact JSON notation for values.", solution: "import json\n\ndata = json.loads(input())\nleaves = []\n\ndef visit(value, path):\n    if isinstance(value, dict):\n        for key, child in value.items():\n            visit(child, key if not path else path + '.' + key)\n    elif isinstance(value, list):\n        for index, child in enumerate(value):\n            visit(child, path + f'[{index}]')\n    else:\n        leaves.append((path, json.dumps(value, separators=(',', ':'))))\n\nvisit(data, '')\nleaves.sort()\nprint(' '.join(f'{path}={value}' for path, value in leaves))", tests: [["{\"user\":{\"name\":\"Ada\",\"scores\":[9,10]},\"active\":true}", "active=true user.name=\"Ada\" user.scores[0]=9 user.scores[1]=10"], ["{\"a\":[null,false,{\"b\":\"x\"}]}", "a[0]=null a[1]=false a[2].b=\"x\""], ["{\"z\":3}", "z=3"]] }),
  p({ difficulty: "hard", id: "v5-csv-revenue-winner", title: "CSV Revenue Winner", tags: ["modules", "csv", "decimal"], summary: "Parse quoted CSV sales records and find the item producing the most exact revenue.", input: "A record count, then CSV rows `item,quantity,unit_price`. Items may contain commas when quoted; quantities are positive integers and prices have at most two decimals.", output: "`ITEM TOTAL` with two decimals. Break equal-revenue ties by lexicographically smaller item name.", solution: "import csv\nfrom decimal import Decimal\n\nbest_item = None\nbest_revenue = None\nfor _ in range(int(input())):\n    item, quantity, price = next(csv.reader([input()]))\n    revenue = Decimal(quantity) * Decimal(price)\n    if best_revenue is None or revenue > best_revenue or (revenue == best_revenue and item < best_item):\n        best_item = item\n        best_revenue = revenue\nprint(best_item, f'{best_revenue:.2f}')", tests: [["3\n\"Tea, Large\",2,3.50\nCoffee,3,2.00\nCake,1,7.00", "Cake 7.00"], ["2\nA,2,1.25\nB,1,3.00", "B 3.00"], ["1\n\"Red Apple\",4,0.50", "Red Apple 2.00"]] }),
  p({ difficulty: "hard", id: "v5-collapse-ipv4-networks", title: "Collapse IPv4 Networks", tags: ["modules", "ipaddress", "networks"], summary: "Combine overlapping or exactly adjacent IPv4 networks into the smallest equivalent CIDR collection.", input: "A positive count followed by valid canonical IPv4 CIDR networks, one per line.", output: "The collapsed CIDR networks in ascending network-address order, separated by spaces.", solution: "import ipaddress\n\nnetworks = [ipaddress.ip_network(input().strip()) for _ in range(int(input()))]\nprint(*ipaddress.collapse_addresses(networks))", tests: [["4\n10.0.0.0/25\n10.0.0.128/25\n10.0.1.0/24\n192.168.0.0/24", "10.0.0.0/23 192.168.0.0/24"], ["1\n172.16.0.0/16", "172.16.0.0/16"], ["2\n10.0.0.0/24\n10.0.2.0/24", "10.0.0.0/24 10.0.2.0/24"]] }),
  p({ difficulty: "hard", id: "v5-cached-domino-tilings", title: "Cached Obstacle Domino Tilings", tags: ["modules", "functions", "functools", "profile-dp"], summary: "Count perfect domino tilings of a two-row board with blocked cells using a cached profile recurrence.", input: "A column count `n <= 200`, then two strings of length `n` using `.` for open and `#` for blocked. The answer fits in Python's integer memory.", output: "The exact number of tilings with 1x2 dominoes; every open cell must be covered once.", solution: "from functools import lru_cache\n\ncolumns = int(input())\nrows = [input(), input()]\nblocked = []\nfor column in range(columns):\n    blocked.append((1 if rows[0][column] == '#' else 0) | (2 if rows[1][column] == '#' else 0))\n\n@lru_cache(None)\ndef solve(column, incoming):\n    if column == columns:\n        return int(incoming == 0)\n    if incoming & blocked[column]:\n        return 0\n    occupied = incoming | blocked[column]\n\n    def fill(row, used, outgoing):\n        while row < 2 and used & (1 << row):\n            row += 1\n        if row == 2:\n            return solve(column + 1, outgoing)\n        total = 0\n        bit = 1 << row\n        if row == 0 and not used & 2:\n            total += fill(2, used | 3, outgoing)\n        if column + 1 < columns and not blocked[column + 1] & bit:\n            total += fill(row + 1, used | bit, outgoing | bit)\n        return total\n\n    return fill(0, occupied, 0)\n\nprint(solve(0, 0))", tests: [["2\n..\n..", "2"], ["3\n...\n...", "3"], ["2\n.#\n#.", "0"]] }),
  p({ difficulty: "hard", id: "v5-zero-one-grid-cost", title: "Zero-One Grid Cost", tags: ["modules", "collections", "graphs"], summary: "Use a deque-based 0-1 BFS to minimize the sum of entered cell costs across a grid.", input: "`rows columns`, then rows of `0` and `1` digits, with at most 200,000 cells. Move four-directionally from the top-left to bottom-right; the starting cell's cost is excluded.", output: "The minimum entry cost.", solution: "from collections import deque\n\nrows, columns = map(int, input().split())\ngrid = [input() for _ in range(rows)]\ninfinity = rows * columns + 1\nbest = [[infinity] * columns for _ in range(rows)]\nbest[0][0] = 0\nqueue = deque([(0, 0)])\nwhile queue:\n    row, column = queue.popleft()\n    for row_change, column_change in ((1, 0), (-1, 0), (0, 1), (0, -1)):\n        next_row = row + row_change\n        next_column = column + column_change\n        if 0 <= next_row < rows and 0 <= next_column < columns:\n            weight = int(grid[next_row][next_column])\n            candidate = best[row][column] + weight\n            if candidate < best[next_row][next_column]:\n                best[next_row][next_column] = candidate\n                if weight == 0:\n                    queue.appendleft((next_row, next_column))\n                else:\n                    queue.append((next_row, next_column))\nprint(best[-1][-1])", tests: [["3 3\n010\n111\n000", "1"], ["2 2\n00\n00", "0"], ["2 3\n111\n111", "3"]] }),
  p({ difficulty: "hard", id: "v5-streaming-lower-medians", title: "Streaming Lower Medians", tags: ["modules", "heapq", "streaming"], summary: "Report the lower median after each arriving value while maintaining two balanced heaps.", input: "A line of integers in arrival order.", output: "The median after every prefix; for an even prefix use the smaller middle value.", solution: "import heapq\n\nlower = []\nupper = []\nanswers = []\nfor value in map(int, input().split()):\n    if not lower or value <= -lower[0]:\n        heapq.heappush(lower, -value)\n    else:\n        heapq.heappush(upper, value)\n    if len(lower) < len(upper):\n        heapq.heappush(lower, -heapq.heappop(upper))\n    elif len(lower) > len(upper) + 1:\n        heapq.heappush(upper, -heapq.heappop(lower))\n    answers.append(-lower[0])\nprint(*answers)", tests: [["5 2 10 1", "5 2 5 2"], ["1 2 3 4 5", "1 1 2 2 3"], ["-1 -5 -3", "-1 -5 -3"]] }),
  p({ difficulty: "hard", id: "v5-bisect-multiset-queries", title: "Bisect Multiset Queries", tags: ["modules", "bisect", "ordered-data"], summary: "Maintain a sorted multiset under insertion, one-copy removal, and kth-order queries.", input: "A command count followed by `ADD x`, `REMOVE x`, or `KTH k`. Removals and one-based kth queries are always valid.", output: "Each `KTH` result on its own line.", solution: "from bisect import bisect_left, insort\n\nvalues = []\nfor _ in range(int(input())):\n    command, number_text = input().split()\n    number = int(number_text)\n    if command == 'ADD':\n        insort(values, number)\n    elif command == 'REMOVE':\n        values.pop(bisect_left(values, number))\n    else:\n        print(values[number - 1])", tests: [["7\nADD 5\nADD 1\nADD 5\nKTH 2\nREMOVE 5\nKTH 2\nKTH 1", "5\n5\n1"], ["5\nADD -2\nADD 9\nKTH 1\nREMOVE -2\nKTH 1", "-2\n9"], ["3\nADD 4\nADD 4\nKTH 2", "4"]] }),
  p({ difficulty: "hard", id: "v5-constrained-circle-seatings", title: "Constrained Circle Seatings", tags: ["modules", "itertools", "combinatorics"], summary: "Count circular seatings of distinct people that avoid forbidden neighboring pairs.", input: "Names on one line, a forbidden-pair count, then unordered name pairs. There are at most 9 names.", output: "The number of valid clockwise orders after fixing the first input name at the first seat. Reverse orders count separately.", solution: "from itertools import permutations\n\nnames = input().split()\nforbidden = {frozenset(input().split()) for _ in range(int(input()))}\nanchor = names[0]\ncount = 0\nfor rest in permutations(names[1:]):\n    circle = (anchor,) + rest\n    valid = True\n    for index in range(len(circle)):\n        if frozenset((circle[index], circle[(index + 1) % len(circle)])) in forbidden:\n            valid = False\n            break\n    if valid:\n        count += 1\nprint(count)", tests: [["A B C D\n1\nA B", "2"], ["A B C\n1\nA B", "0"], ["A B C D\n0", "6"]] }),
  p({ difficulty: "hard", id: "v5-business-minute-distance", title: "Business-Minute Distance", tags: ["modules", "datetime", "scheduling"], summary: "Measure elapsed working minutes while excluding nights and weekends.", input: "Two ISO local timestamps `YYYY-MM-DDTHH:MM`, start then end, with start no later than end and at most 366 days apart.", output: "Minutes lying on Monday-Friday within the half-open work window `[09:00,17:00)`.", solution: "from datetime import datetime, time, timedelta\n\nstart = datetime.fromisoformat(input())\nend = datetime.fromisoformat(input())\nday = start.date()\ntotal = 0\nwhile day <= end.date():\n    if day.weekday() < 5:\n        opening = datetime.combine(day, time(9, 0))\n        closing = datetime.combine(day, time(17, 0))\n        overlap_start = max(start, opening)\n        overlap_end = min(end, closing)\n        if overlap_start < overlap_end:\n            total += int((overlap_end - overlap_start).total_seconds() // 60)\n    day += timedelta(days=1)\nprint(total)", tests: [["2026-07-17T16:00\n2026-07-20T10:00", "120"], ["2026-07-20T08:30\n2026-07-20T18:00", "480"], ["2026-07-18T10:00\n2026-07-19T16:00", "0"]] }),
  p({ difficulty: "hard", id: "v5-linear-regression-line", title: "Least-Squares Regression Line", tags: ["modules", "statistics", "data-analysis"], summary: "Fit the least-squares line `y = slope*x + intercept` to paired observations.", input: "Distinct x-coordinates on one line and the same number of y-coordinates on the next; at least two pairs are supplied.", output: "The slope and intercept to three decimal places.", solution: "import statistics\n\nx_values = list(map(float, input().split()))\ny_values = list(map(float, input().split()))\nslope, intercept = statistics.linear_regression(x_values, y_values)\nprint(f'{slope:.3f} {intercept:.3f}')", tests: [["1 2 3\n2 4 6", "2.000 0.000"], ["0 1 2\n1 3 5", "2.000 1.000"], ["-1 0 1\n4 1 -2", "-3.000 1.000"]] }),
  p({ difficulty: "hard", id: "v5-largest-remainder-split", title: "Largest-Remainder Cent Split", tags: ["modules", "decimal", "rounding"], summary: "Split an exact money total proportionally while distributing leftover cents by largest fractional remainder.", input: "A nonnegative decimal total with two places, then positive integer weights on one line.", output: "One two-decimal allocation per weight. Tied remainders favor the lower input index, and allocations must sum exactly to the total.", solution: "from decimal import Decimal\n\ncents = int(Decimal(input()) * 100)\nweights = list(map(int, input().split()))\nweight_sum = sum(weights)\nshares = []\nremainders = []\nfor weight in weights:\n    share, remainder = divmod(cents * weight, weight_sum)\n    shares.append(share)\n    remainders.append(remainder)\nremaining = cents - sum(shares)\norder = sorted(range(len(weights)), key=lambda index: (-remainders[index], index))\nfor index in order[:remaining]:\n    shares[index] += 1\nprint(' '.join(f'{Decimal(share) / 100:.2f}' for share in shares))", tests: [["10.00\n1 1 1", "3.34 3.33 3.33"], ["0.05\n1 2", "0.02 0.03"], ["12.34\n2 1", "8.23 4.11"]] }),
];

const classProblems: Problem[] = [
  p({ difficulty: "hard", id: "v5-union-find-console", title: "Union-Find Console", tags: ["classes", "graphs", "disjoint-sets"], summary: "Build a disjoint-set object with path compression and union by size, then answer connectivity and component-size commands.", input: "`n q`, followed by `q` commands: `UNION a b`, `CONNECTED a b`, or `SIZE a`, with nodes `0..n-1`.", output: "For each query command, print `yes`/`no` or the component size on its own line.", solution: "class UnionFind:\n    def __init__(self, size):\n        self.parent = list(range(size))\n        self.sizes = [1] * size\n\n    def find(self, node):\n        while self.parent[node] != node:\n            self.parent[node] = self.parent[self.parent[node]]\n            node = self.parent[node]\n        return node\n\n    def union(self, left, right):\n        left = self.find(left)\n        right = self.find(right)\n        if left == right:\n            return\n        if self.sizes[left] < self.sizes[right]:\n            left, right = right, left\n        self.parent[right] = left\n        self.sizes[left] += self.sizes[right]\n\n    def size(self, node):\n        return self.sizes[self.find(node)]\n\nn, command_count = map(int, input().split())\ngroups = UnionFind(n)\nfor _ in range(command_count):\n    command = input().split()\n    if command[0] == 'UNION':\n        groups.union(int(command[1]), int(command[2]))\n    elif command[0] == 'CONNECTED':\n        print('yes' if groups.find(int(command[1])) == groups.find(int(command[2])) else 'no')\n    else:\n        print(groups.size(int(command[1])))", tests: [["5 7\nUNION 0 1\nUNION 1 2\nCONNECTED 0 2\nSIZE 1\nCONNECTED 0 4\nUNION 3 4\nSIZE 4", "yes\n3\nno\n2"], ["3 4\nCONNECTED 0 0\nUNION 0 2\nSIZE 2\nCONNECTED 1 2", "yes\n2\nno"], ["1 2\nSIZE 0\nCONNECTED 0 0", "1\nyes"]] }),
  p({ difficulty: "hard", id: "v5-fenwick-range-console", title: "Fenwick Range Console", tags: ["classes", "prefix-sums", "data-structures"], summary: "Create a Fenwick tree that supports point additions and inclusive range-sum queries.", input: "Initial integers, a command count, then `ADD index delta` or `SUM left right` commands using zero-based inclusive indices.", output: "Each requested range sum on its own line.", solution: "class FenwickTree:\n    def __init__(self, values):\n        self.tree = [0] * (len(values) + 1)\n        for index, value in enumerate(values):\n            self.add(index, value)\n\n    def add(self, index, delta):\n        index += 1\n        while index < len(self.tree):\n            self.tree[index] += delta\n            index += index & -index\n\n    def prefix(self, end):\n        total = 0\n        while end > 0:\n            total += self.tree[end]\n            end -= end & -end\n        return total\n\n    def range_sum(self, left, right):\n        return self.prefix(right + 1) - self.prefix(left)\n\ntree = FenwickTree(list(map(int, input().split())))\nfor _ in range(int(input())):\n    command, first, second = input().split()\n    if command == 'ADD':\n        tree.add(int(first), int(second))\n    else:\n        print(tree.range_sum(int(first), int(second)))", tests: [["1 2 3 4\n5\nSUM 0 3\nADD 1 5\nSUM 1 2\nADD 3 -4\nSUM 2 3", "10\n10\n3"], ["5\n3\nSUM 0 0\nADD 0 -2\nSUM 0 0", "5\n3"], ["-1 4 -2\n2\nSUM 0 2\nSUM 1 1", "1\n4"]] }),
  p({ difficulty: "hard", id: "v5-lazy-range-minimum", title: "Lazy Range-Minimum Tree", tags: ["classes", "segment-trees", "data-structures"], summary: "Implement lazy propagation for inclusive range additions and range-minimum queries.", input: "Initial integers, a command count, then `ADD left right delta` or `MIN left right` using valid zero-based inclusive ranges.", output: "Each queried minimum on its own line.", solution: "class LazyMinimumTree:\n    def __init__(self, values):\n        self.size = len(values)\n        self.tree = [0] * (4 * self.size)\n        self.lazy = [0] * (4 * self.size)\n        self.build(1, 0, self.size - 1, values)\n\n    def build(self, node, left, right, values):\n        if left == right:\n            self.tree[node] = values[left]\n            return\n        middle = (left + right) // 2\n        self.build(node * 2, left, middle, values)\n        self.build(node * 2 + 1, middle + 1, right, values)\n        self.tree[node] = min(self.tree[node * 2], self.tree[node * 2 + 1])\n\n    def push(self, node):\n        if self.lazy[node]:\n            for child in (node * 2, node * 2 + 1):\n                self.tree[child] += self.lazy[node]\n                self.lazy[child] += self.lazy[node]\n            self.lazy[node] = 0\n\n    def add(self, query_left, query_right, delta, node=1, left=0, right=None):\n        if right is None:\n            right = self.size - 1\n        if query_left <= left and right <= query_right:\n            self.tree[node] += delta\n            self.lazy[node] += delta\n            return\n        self.push(node)\n        middle = (left + right) // 2\n        if query_left <= middle:\n            self.add(query_left, query_right, delta, node * 2, left, middle)\n        if query_right > middle:\n            self.add(query_left, query_right, delta, node * 2 + 1, middle + 1, right)\n        self.tree[node] = min(self.tree[node * 2], self.tree[node * 2 + 1])\n\n    def minimum(self, query_left, query_right, node=1, left=0, right=None):\n        if right is None:\n            right = self.size - 1\n        if query_left <= left and right <= query_right:\n            return self.tree[node]\n        self.push(node)\n        middle = (left + right) // 2\n        answer = 10 ** 30\n        if query_left <= middle:\n            answer = min(answer, self.minimum(query_left, query_right, node * 2, left, middle))\n        if query_right > middle:\n            answer = min(answer, self.minimum(query_left, query_right, node * 2 + 1, middle + 1, right))\n        return answer\n\ntree = LazyMinimumTree(list(map(int, input().split())))\nfor _ in range(int(input())):\n    command = input().split()\n    if command[0] == 'ADD':\n        tree.add(int(command[1]), int(command[2]), int(command[3]))\n    else:\n        print(tree.minimum(int(command[1]), int(command[2])))", tests: [["5 1 7 3 9\n5\nMIN 0 4\nADD 1 3 -2\nMIN 0 2\nADD 0 4 4\nMIN 3 4", "1\n-1\n5"], ["2 2 2\n4\nADD 0 2 3\nMIN 1 1\nADD 1 2 -7\nMIN 0 2", "5\n-2"], ["-5\n3\nMIN 0 0\nADD 0 0 10\nMIN 0 0", "-5\n5"]] }),
  p({ difficulty: "hard", id: "v5-trie-autocomplete", title: "Trie Autocomplete", tags: ["classes", "tries", "strings"], summary: "Store unique words in a trie and return the first three lexicographic completions of each prefix.", input: "A word count, lowercase words on separate lines, a query count, then lowercase prefixes.", output: "For each prefix, comma-join up to three suggestions; print `none` if there are no completions.", solution: "class Trie:\n    def __init__(self):\n        self.root = {}\n\n    def add(self, word):\n        node = self.root\n        for character in word:\n            node = node.setdefault(character, {})\n        node['$'] = {}\n\n    def suggestions(self, prefix, limit=3):\n        node = self.root\n        for character in prefix:\n            if character not in node:\n                return []\n            node = node[character]\n        answers = []\n\n        def collect(current, suffix):\n            if len(answers) == limit:\n                return\n            if '$' in current:\n                answers.append(prefix + suffix)\n            for character in sorted(key for key in current if key != '$'):\n                collect(current[character], suffix + character)\n\n        collect(node, '')\n        return answers\n\ntrie = Trie()\nfor _ in range(int(input())):\n    trie.add(input())\nfor _ in range(int(input())):\n    answers = trie.suggestions(input())\n    print(','.join(answers) if answers else 'none')", tests: [["4\ncar\ncart\ncat\ndog\n3\nca\ncart\nz", "car,cart,cat\ncart\nnone"], ["4\nalpha\nalpine\nalps\nbeta\n2\nal\nalp", "alpha,alpine,alps\nalpha,alpine,alps"], ["1\ncode\n2\nc\ncode", "code\ncode"]] }),
  p({ difficulty: "hard", id: "v5-dynamic-range-set", title: "Dynamic Range Set", tags: ["classes", "intervals", "state"], summary: "Maintain the union of half-open integer intervals while additions merge coverage and removals may split it.", input: "A command count followed by `ADD start end`, `REMOVE start end`, or `LENGTH`, with `start < end` for interval commands.", output: "For every `LENGTH`, print the total covered length on its own line.", solution: "class RangeSet:\n    def __init__(self):\n        self.intervals = []\n\n    def add(self, start, end):\n        merged = []\n        placed = False\n        for left, right in self.intervals:\n            if right < start:\n                merged.append((left, right))\n            elif end < left:\n                if not placed:\n                    merged.append((start, end))\n                    placed = True\n                merged.append((left, right))\n            else:\n                start = min(start, left)\n                end = max(end, right)\n        if not placed:\n            merged.append((start, end))\n        self.intervals = merged\n\n    def remove(self, start, end):\n        remaining = []\n        for left, right in self.intervals:\n            if right <= start or end <= left:\n                remaining.append((left, right))\n            else:\n                if left < start:\n                    remaining.append((left, start))\n                if end < right:\n                    remaining.append((end, right))\n        self.intervals = remaining\n\n    def length(self):\n        return sum(right - left for left, right in self.intervals)\n\nranges = RangeSet()\nfor _ in range(int(input())):\n    command = input().split()\n    if command[0] == 'ADD':\n        ranges.add(int(command[1]), int(command[2]))\n    elif command[0] == 'REMOVE':\n        ranges.remove(int(command[1]), int(command[2]))\n    else:\n        print(ranges.length())", tests: [["8\nADD 1 5\nADD 8 10\nADD 3 9\nLENGTH\nREMOVE 4 7\nLENGTH\nADD 4 7\nLENGTH", "9\n6\n9"], ["5\nADD 0 10\nREMOVE 2 8\nLENGTH\nREMOVE -1 1\nLENGTH", "4\n3"], ["4\nADD 1 2\nADD 2 3\nREMOVE 1 3\nLENGTH", "0"]] }),
  p({ difficulty: "hard", id: "v5-undo-redo-editor", title: "Undo-Redo Text Editor", tags: ["classes", "state", "stacks"], summary: "Model a text editor with branching undo and redo history.", input: "A command count followed by `TYPE text`, `DELETE k`, `UNDO`, `REDO`, or `PRINT`. Typed text has no spaces; every delete satisfies `1 <= k <= current text length`, and history commands are valid. A new edit clears redo history.", output: "The current text for every `PRINT`, one result per line.", solution: "class TextEditor:\n    def __init__(self):\n        self.text = ''\n        self.undo_history = []\n        self.redo_history = []\n\n    def edit(self, new_text):\n        self.undo_history.append(self.text)\n        self.text = new_text\n        self.redo_history.clear()\n\n    def type(self, text):\n        self.edit(self.text + text)\n\n    def delete(self, amount):\n        self.edit(self.text[:-amount])\n\n    def undo(self):\n        self.redo_history.append(self.text)\n        self.text = self.undo_history.pop()\n\n    def redo(self):\n        self.undo_history.append(self.text)\n        self.text = self.redo_history.pop()\n\neditor = TextEditor()\nfor _ in range(int(input())):\n    command = input().split()\n    if command[0] == 'TYPE': editor.type(command[1])\n    elif command[0] == 'DELETE': editor.delete(int(command[1]))\n    elif command[0] == 'UNDO': editor.undo()\n    elif command[0] == 'REDO': editor.redo()\n    else: print(editor.text)", tests: [["8\nTYPE abc\nTYPE de\nDELETE 2\nPRINT\nUNDO\nPRINT\nREDO\nPRINT", "abc\nabcde\nabc"], ["7\nTYPE hello\nDELETE 3\nPRINT\nUNDO\nPRINT\nTYPE x\nPRINT", "he\nhello\nhellox"], ["6\nTYPE a\nTYPE b\nUNDO\nUNDO\nTYPE x\nPRINT", "x"]] }),
  p({ difficulty: "hard", id: "v5-no-triple-calendar", title: "No-Triple-Booking Calendar", tags: ["classes", "intervals", "state"], summary: "Accept half-open event bookings unless they would create a time covered by three events.", input: "A booking count followed by `start end` integer intervals with `start < end`, processed in order.", output: "`accepted` or `rejected` for every request. Rejected requests do not change the calendar.", solution: "class DoubleBookingCalendar:\n    def __init__(self):\n        self.bookings = []\n        self.double_booked = []\n\n    def book(self, start, end):\n        for left, right in self.double_booked:\n            if max(start, left) < min(end, right):\n                return False\n        for left, right in self.bookings:\n            overlap_start = max(start, left)\n            overlap_end = min(end, right)\n            if overlap_start < overlap_end:\n                self.double_booked.append((overlap_start, overlap_end))\n        self.bookings.append((start, end))\n        return True\n\ncalendar = DoubleBookingCalendar()\nfor _ in range(int(input())):\n    start, end = map(int, input().split())\n    print('accepted' if calendar.book(start, end) else 'rejected')", tests: [["6\n10 20\n50 60\n10 40\n5 15\n5 10\n25 55", "accepted\naccepted\naccepted\nrejected\naccepted\naccepted"], ["3\n1 5\n2 6\n3 4", "accepted\naccepted\nrejected"], ["3\n0 1\n1 2\n0 2", "accepted\naccepted\naccepted"]] }),
  p({ difficulty: "hard", id: "v5-price-time-order-book", title: "Price-Time Order Book", tags: ["classes", "modules", "heaps", "simulation"], summary: "Match limit buy and sell orders using best price first and arrival time to break price ties.", input: "A command count, then `BUY id price quantity` or `SELL id price quantity`. IDs are unique and prices and quantities are positive integers.", output: "Each trade as `buyId-sellId@pricexquantity`, or `none` if no trade occurs. A trade uses the resting order's price.", solution: "import heapq\n\nclass OrderBook:\n    def __init__(self):\n        self.buys = []\n        self.sells = []\n        self.time = 0\n\n    def submit(self, side, order_id, price, quantity):\n        trades = []\n        if side == 'BUY':\n            while quantity and self.sells and self.sells[0][0] <= price:\n                sell_price, time, sell_id, sell_quantity = heapq.heappop(self.sells)\n                amount = min(quantity, sell_quantity)\n                trades.append(f'{order_id}-{sell_id}@{sell_price}x{amount}')\n                quantity -= amount\n                sell_quantity -= amount\n                if sell_quantity:\n                    heapq.heappush(self.sells, (sell_price, time, sell_id, sell_quantity))\n            if quantity:\n                heapq.heappush(self.buys, (-price, self.time, order_id, quantity))\n        else:\n            while quantity and self.buys and -self.buys[0][0] >= price:\n                negative_price, time, buy_id, buy_quantity = heapq.heappop(self.buys)\n                buy_price = -negative_price\n                amount = min(quantity, buy_quantity)\n                trades.append(f'{buy_id}-{order_id}@{buy_price}x{amount}')\n                quantity -= amount\n                buy_quantity -= amount\n                if buy_quantity:\n                    heapq.heappush(self.buys, (-buy_price, time, buy_id, buy_quantity))\n            if quantity:\n                heapq.heappush(self.sells, (price, self.time, order_id, quantity))\n        self.time += 1\n        return trades\n\nbook = OrderBook()\nall_trades = []\nfor _ in range(int(input())):\n    side, order_id, price, quantity = input().split()\n    all_trades += book.submit(side, order_id, int(price), int(quantity))\nif all_trades:\n    for trade in all_trades:\n        print(trade)\nelse:\n    print('none')", tests: [["5\nBUY B1 100 5\nSELL S1 90 2\nSELL S2 100 4\nBUY B2 105 2\nSELL S3 110 1", "B1-S1@100x2\nB1-S2@100x3\nB2-S2@100x1"], ["3\nSELL S1 50 3\nBUY B1 60 2\nBUY B2 50 1", "B1-S1@50x2\nB2-S1@50x1"], ["2\nBUY B1 10 1\nSELL S1 11 1", "none"]] }),
  p({ difficulty: "hard", id: "v5-timestamped-value-store", title: "Timestamped Value Store", tags: ["classes", "searching", "state"], summary: "Store versions of each key and retrieve the newest value not later than a query timestamp.", input: "A command count followed by `SET key timestamp value` or `GET key timestamp`. SET timestamps are strictly increasing per key; tokens contain no spaces.", output: "Each fetched value, or `none` if no version is old enough, on its own line.", solution: "class TimeMap:\n    def __init__(self):\n        self.history = {}\n\n    def set(self, key, timestamp, value):\n        self.history.setdefault(key, []).append((timestamp, value))\n\n    def get(self, key, timestamp):\n        versions = self.history.get(key, [])\n        low, high = 0, len(versions)\n        while low < high:\n            middle = (low + high) // 2\n            if versions[middle][0] <= timestamp:\n                low = middle + 1\n            else:\n                high = middle\n        return 'none' if low == 0 else versions[low - 1][1]\n\nstore = TimeMap()\nfor _ in range(int(input())):\n    command = input().split()\n    if command[0] == 'SET':\n        store.set(command[1], int(command[2]), command[3])\n    else:\n        print(store.get(command[1], int(command[2])))", tests: [["7\nSET color 1 red\nSET color 5 blue\nGET color 0\nGET color 1\nGET color 4\nGET color 5\nGET other 9", "none\nred\nred\nblue\nnone"], ["4\nSET x 10 a\nSET x 20 b\nGET x 100\nGET x 15", "b\na"], ["3\nSET a 2 one\nSET b 1 two\nGET b 1", "two"]] }),
  p({ difficulty: "hard", id: "v5-ancestor-jump-table", title: "Ancestor Jump Table", tags: ["classes", "trees", "binary-lifting"], summary: "Precompute powers-of-two parent jumps so distant ancestor queries can be answered logarithmically.", input: "A node count `2 <= n <= 200,000`, parents of nodes `1..n-1` on one line (each parent index is smaller than its child), a query count, then `node k` lines with `0 <= k <= 10^18`.", output: "For each query, print the ancestor `k` edges above the node, or `-1` if that lies above root 0.", solution: "class AncestorTable:\n    def __init__(self, parents):\n        first = [-1] + parents\n        self.jumps = [first]\n        for _ in range(len(first).bit_length()):\n            previous = self.jumps[-1]\n            current = []\n            for node in range(len(first)):\n                middle = previous[node]\n                current.append(-1 if middle == -1 else previous[middle])\n            self.jumps.append(current)\n\n    def ancestor(self, node, steps):\n        bit = 0\n        while steps and node != -1:\n            if bit >= len(self.jumps):\n                return -1\n            if steps & 1:\n                node = self.jumps[bit][node]\n            steps >>= 1\n            bit += 1\n        return node\n\nsize = int(input())\ntable = AncestorTable(list(map(int, input().split())))\nfor _ in range(int(input())):\n    node, steps = map(int, input().split())\n    print(table.ancestor(node, steps))", tests: [["7\n0 0 1 1 2 2\n5\n6 1\n6 2\n6 3\n4 2\n3 0", "2\n0\n-1\n0\n3"], ["5\n0 1 2 3\n3\n4 4\n4 5\n2 1", "0\n-1\n1"], ["4\n0 0 0\n3\n3 1\n3 2\n0 0", "0\n-1\n0"]] }),
  p({ difficulty: "hard", id: "v5-first-fit-memory", title: "First-Fit Memory Allocator", tags: ["classes", "intervals", "simulation"], summary: "Allocate contiguous memory by first fit, then free blocks and coalesce adjacent free space.", input: "A positive memory size, a command count, then `ALLOC id length`, `FREE id`, or `MAP`. Allocation IDs are unique until freed and FREE IDs exist.", output: "For `ALLOC`, print its start index or `-1`. For `MAP`, print free blocks as `start:length`, or `none` if memory is full.", solution: "class MemoryAllocator:\n    def __init__(self, size):\n        self.free_blocks = [(0, size)]\n        self.allocated = {}\n\n    def allocate(self, identifier, length):\n        for index, (start, available) in enumerate(self.free_blocks):\n            if available >= length:\n                self.allocated[identifier] = (start, length)\n                if available == length:\n                    self.free_blocks.pop(index)\n                else:\n                    self.free_blocks[index] = (start + length, available - length)\n                return start\n        return -1\n\n    def free(self, identifier):\n        self.free_blocks.append(self.allocated.pop(identifier))\n        self.free_blocks.sort()\n        merged = []\n        for start, length in self.free_blocks:\n            if merged and merged[-1][0] + merged[-1][1] == start:\n                previous_start, previous_length = merged[-1]\n                merged[-1] = (previous_start, previous_length + length)\n            else:\n                merged.append((start, length))\n        self.free_blocks = merged\n\n    def memory_map(self):\n        return ' '.join(f'{start}:{length}' for start, length in self.free_blocks) or 'none'\n\nallocator = MemoryAllocator(int(input()))\nfor _ in range(int(input())):\n    command = input().split()\n    if command[0] == 'ALLOC':\n        print(allocator.allocate(command[1], int(command[2])))\n    elif command[0] == 'FREE':\n        allocator.free(command[1])\n    else:\n        print(allocator.memory_map())", tests: [["10\n9\nALLOC A 4\nALLOC B 3\nFREE A\nALLOC C 5\nFREE B\nALLOC C 5\nMAP\nFREE C\nMAP", "0\n4\n-1\n0\n5:5\n0:10"], ["6\n6\nALLOC X 2\nALLOC Y 2\nFREE X\nALLOC Z 3\nFREE Y\nMAP", "0\n2\n-1\n0:6"], ["3\n3\nALLOC A 3\nMAP\nFREE A", "0\nnone"]] }),
];

